window.COURSE_REGISTRY = window.COURSE_REGISTRY || {};
window.COURSE_REGISTRY["c36-plumbing"] = [
  {id:1, block:1, sec:"Pipe Materials & Selection", q:"Which copper water tube has the thickest wall and is preferred for underground water service?", opts:["Type M","Type L","Type K","Type DWV"], correct:2, re:"Type K has the heaviest wall of the common water tubes, so it is used underground and where high pressure or mechanical protection is needed."},
  {id:2, block:1, sec:"Pipe Materials & Selection", q:"Which plastic pipe is listed for hot- and cold-water distribution inside a building?", opts:["PVC","CPVC","ABS","Cast iron"], correct:1, re:"CPVC is chlorinated PVC formulated to withstand hot water; ordinary PVC is not rated for hot-water distribution."},
  {id:3, block:1, sec:"Pipe Materials & Selection", q:"Black ABS pipe in a building is most commonly used for:", opts:["Drain, waste, and vent piping","Pressurized hot water","Natural-gas supply","Potable cold water under pressure"], correct:0, re:"ABS is a black thermoplastic widely used for DWV (drain, waste, and vent) piping, not for pressurized water service."},
  {id:4, block:1, sec:"Pipe Materials & Selection", q:"Type L copper tube is most commonly used for:", opts:["Interior residential water-supply lines","Buried fire-service mains only","Drain and vent piping only","Fuel-gas piping only"], correct:0, re:"Type L has a medium wall thickness and is the most common copper tube for interior water-supply distribution."},
  {id:5, block:1, sec:"Pipe Materials & Selection", q:"Compared with Type K and Type L, Type M copper tube has:", opts:["A heavier wall than K","An identical wall to K","The thinnest wall of the three","No water-service use at all"], correct:2, re:"Type M has the thinnest wall of the three; some jurisdictions restrict where Type M may be used for water supply."},
  {id:6, block:1, sec:"Pipe Materials & Selection", q:"Galvanized steel water pipe has largely fallen out of favor because, over time, it:", opts:["Cannot be threaded","Cannot carry cold water","Is too flexible to support","Corrodes internally and restricts flow"], correct:3, re:"The internal zinc coating eventually wears away and the steel rusts, narrowing the bore, restricting flow, and causing leaks."},
  {id:7, block:1, sec:"Pipe Materials & Selection", q:"PEX tubing is best described as:", opts:["A rigid metallic pipe","A clay drainage product","A flexible cross-linked polyethylene tubing","A rigid fiberglass conduit"], correct:2, re:"PEX is cross-linked polyethylene, a flexible plastic tubing used for hot- and cold-water distribution and joined with mechanical fittings."},
  {id:8, block:1, sec:"Pipe Materials & Selection", q:"Hubless (no-hub) cast iron pipe is used primarily for:", opts:["Pressurized potable water","Fuel-gas distribution","Compressed-air lines","Sanitary drain, waste, and vent piping"], correct:3, re:"No-hub cast iron is a gravity DWV material valued for its strength and quietness, not for pressurized service."},
  {id:9, block:1, sec:"Pipe Materials & Selection", q:"Which material is NOT approved for potable hot-water distribution?", opts:["Type L copper","CPVC","Plain PVC","PEX"], correct:2, re:"Plain PVC is rated only for cold water and DWV; copper, CPVC, and PEX are all listed for hot-water distribution."},
  {id:10, block:1, sec:"Pipe Materials & Selection", q:"One key advantage of cast iron drainage pipe over plastic DWV pipe is that it:", opts:["Deadens the sound of flowing water","Is lighter to handle","Costs less","Never needs support"], correct:0, re:"The mass of cast iron muffles the noise of water moving through the pipe, a benefit in occupied buildings."},
  {id:11, block:1, sec:"Pipe Materials & Selection", q:"Brass pipe and fittings used in plumbing are an alloy primarily of:", opts:["Iron and carbon","Lead and antimony","Aluminum and tin","Copper and zinc"], correct:3, re:"Brass is mainly copper and zinc; potable-water brass must also meet lead-free limits."},
  {id:12, block:1, sec:"Pipe Materials & Selection", q:"For an underground building water-service line, an installer is most likely to choose:", opts:["Type M copper or thin-wall pipe","ABS DWV pipe","Type K copper or other approved pressure-rated pipe","Cellular-core PVC"], correct:2, re:"Underground water service needs a heavy, durable, pressure-rated material such as Type K copper or another approved water-service pipe."},
  {id:13, block:1, sec:"Pipe Materials & Selection", q:"PVC pipe is suitable for:", opts:["Cold-water and DWV applications","Hot-water distribution at 180 F","Fuel-gas piping","Steam lines"], correct:0, re:"PVC is rated for cold water and drainage; it softens at hot-water temperatures and is not used for hot supply, gas, or steam."},
  {id:14, block:1, sec:"Pipe Materials & Selection", q:"Which tubing is commonly run in long continuous coils to reduce the number of fittings inside walls?", opts:["Cast iron","Rigid copper","PEX","Galvanized steel"], correct:2, re:"Flexible PEX can be run in long coils from a manifold to each fixture, reducing concealed fittings and potential leak points."},
  {id:15, block:1, sec:"Pipe Materials & Selection", q:"Soft (annealed) copper tube differs from hard-drawn copper in that it:", opts:["Has a thinner wall in every case","Is only used for gas","Cannot be soldered","Can be bent by hand and is sold in coils"], correct:3, re:"Soft copper is annealed so it can be bent and coiled; hard-drawn copper is rigid and supplied in straight lengths."},
  {id:16, block:1, sec:"Pipe Materials & Selection", q:"Which of these is a thermoplastic DWV pipe rather than a metal?", opts:["No-hub cast iron","Galvanized steel","ABS","Red brass"], correct:2, re:"ABS (acrylonitrile butadiene styrene) is a black plastic DWV pipe; the others are metals."},
  {id:17, block:1, sec:"Pipe Materials & Selection", q:"A common reason to select copper over plastic for water piping is that copper:", opts:["Tolerates higher temperatures and is rigid and durable","Is immune to all corrosion","Is always cheaper","Needs no fittings"], correct:0, re:"Copper withstands high temperatures, is rigid and long-lasting, and is widely accepted, though it costs more than plastic."},
  {id:18, block:1, sec:"Pipe Materials & Selection", q:"Extra-heavy and service-weight are wall-thickness classes associated with:", opts:["PEX tubing","Soft copper","CPVC pipe","Cast iron soil pipe"], correct:3, re:"Hub-and-spigot cast iron soil pipe is made in service-weight and extra-heavy classes that differ in wall thickness."},
  {id:19, block:1, sec:"Pipe Materials & Selection", q:"Which statement about ABS and PVC DWV pipe is correct?", opts:["Both are metallic","Both are rated for hot-water supply","ABS is typically black and PVC is typically white","Neither can be used for drainage"], correct:2, re:"ABS DWV pipe is usually black and PVC DWV pipe is usually white; both are plastic drainage materials, not pressure pipe."},
  {id:20, block:1, sec:"Pipe Materials & Selection", q:"A pipe material's pressure rating generally decreases as:", opts:["Its wall gets thinner","Its wall gets thicker","Its length increases","Its color changes"], correct:0, re:"For a given diameter and material, a thinner wall carries less pressure, which is why Type M copper is rated below Type K."},
  {id:21, block:1, sec:"Joining Methods", q:"Rigid PVC and CPVC pipe are normally joined by:", opts:["Soldering with flux","No-hub bands","Crimp rings","Solvent cement (with primer on PVC/CPVC)"], correct:3, re:"PVC and CPVC are chemically welded with solvent cement; the solvent softens and fuses the surfaces into one piece."},
  {id:22, block:1, sec:"Joining Methods", q:"Copper water tube and fittings are most often joined by:", opts:["Solvent welding","Threading the soft copper","Soldering, also called sweating","Cold-crimping with tape"], correct:2, re:"Copper joints are commonly soldered (sweated) using flux and lead-free solder to draw the molten solder into the cup by capillary action."},
  {id:23, block:1, sec:"Joining Methods", q:"PEX water tubing is commonly joined using:", opts:["Solvent cement","Lead-and-oakum joints","Brazing","Crimp, expansion, or push-fit fittings"], correct:3, re:"PEX is flexible and joined mechanically with crimp rings, cold-expansion fittings, or push-fit fittings rather than with cement or solder."},
  {id:24, block:1, sec:"Joining Methods", q:"The purpose of primer applied before PVC solvent cement is to:", opts:["Color the joint for inspection only","Cure the cement faster after assembly","Lubricate the pipe for assembly","Soften and clean the surface so the cement can fuse it"], correct:3, re:"Primer softens and conditions the PVC/CPVC surface and removes contamination so the solvent cement can properly fuse the joint."},
  {id:25, block:1, sec:"Joining Methods", q:"Hubless (no-hub) cast iron pipe is joined with:", opts:["A neoprene gasket inside a stainless-steel shielded clamp","Molten lead and oakum","Solvent cement","A flared brass nut"], correct:0, re:"No-hub joints use an elastomeric (neoprene) gasket housed in a corrugated stainless-steel shield with clamping bands tightened to a set torque."},
  {id:26, block:1, sec:"Joining Methods", q:"A press (press-fit) copper joint is made by:", opts:["Compressing a fitting with an internal O-ring onto the tube with a pressing tool","Heating the fitting with a torch","Threading the tube into the fitting","Gluing the tube with solvent cement"], correct:0, re:"Press fittings contain an O-ring; a pressing tool crimps the fitting onto the tube to form a watertight mechanical seal with no flame."},
  {id:27, block:1, sec:"Joining Methods", q:"A key safety advantage of press fittings over soldering is that they:", opts:["Require an open flame","Must be done on dry pipe only","Need no flame, flux, or solder","Cannot be inspected"], correct:2, re:"Press joints are made cold with a tool, eliminating the open flame and hot-work hazard associated with soldering."},
  {id:28, block:1, sec:"Joining Methods", q:"A flared joint on soft copper is made by:", opts:["Expanding the tube end to a 45-degree cone held by a flare nut","Melting solder into the cup","Cementing the tube into a socket","Crimping a ring over a barb"], correct:0, re:"The soft-copper tube end is flared to a 45-degree cone and clamped against the fitting seat by a flare nut, a method used for fuel-gas and similar connections."},
  {id:29, block:1, sec:"Joining Methods", q:"When joining two different drainage plastics such as ABS and PVC, the recommended method is to:", opts:["Tape the joint","Heat both ends and press them together","Thread the plastics together","Use an approved transition coupling or transition cement"], correct:3, re:"Different plastics should be joined with an approved transition coupling (or listed transition cement) rather than mixing their individual cements."},
  {id:30, block:1, sec:"Joining Methods", q:"Lead-and-oakum (caulked) joints are associated with:", opts:["PEX tubing","Soft copper gas lines","CPVC pipe","Hub-and-spigot cast iron soil pipe"], correct:3, re:"The traditional hub-and-spigot cast iron joint packs oakum into the hub and then pours molten lead over it; gasketed joints have largely replaced it."},
  {id:31, block:1, sec:"Joining Methods", q:"Soldering flux is applied to a copper joint mainly to:", opts:["Increase water pressure","Add color to the fitting","Clean the metal and help solder flow into the joint","Slow the solder down"], correct:2, re:"Flux removes oxides and lets the molten solder wet and flow into the joint by capillary action for a sound seal."},
  {id:32, block:1, sec:"Joining Methods", q:"Threaded steel or brass pipe joints are sealed with:", opts:["Solvent cement","Pipe-joint compound or PTFE thread tape on the threads","A neoprene gasket sleeve","An O-ring press"], correct:1, re:"Tapered (NPT) threads are sealed with pipe-joint compound (pipe dope) or PTFE tape to fill the thread spiral and prevent leaks."},
  {id:33, block:1, sec:"Joining Methods", q:"A push-fit (push-to-connect) fitting holds the pipe with:", opts:["Solvent cement inside the socket","A welded bead","A poured-lead collar","Internal gripping teeth and an O-ring seal"], correct:3, re:"Push-fit fittings use stainless gripping teeth to hold the pipe and an O-ring to seal it, allowing a no-tool connection on copper, CPVC, or PEX."},
  {id:34, block:1, sec:"Joining Methods", q:"Cold-expansion PEX connections work by:", opts:["Melting the tube to the fitting","Caulking the joint with lead","Gluing the tube into a socket","Expanding the tube and ring, then letting them shrink back over the fitting"], correct:3, re:"With cold-expansion (e.g., PEX-A) the tube and an expansion ring are stretched, the fitting is inserted, and the memory of the material shrinks them tight around it."},
  {id:35, block:1, sec:"Joining Methods", q:"Why must solvent-cemented PVC joints be allowed proper set and cure time before pressurizing?", opts:["So the primer can dry to a color","To let the pipe cool from soldering","So the solvent can develop the joint's full strength","To allow the threads to seat"], correct:2, re:"Solvent welds need time to set and cure so the fused bond reaches full strength before the line is pressurized; rushing it can cause failures."},
  {id:36, block:1, sec:"Joining Methods", q:"On a soldered copper joint, capillary action refers to:", opts:["Water pressure pushing solder out","The flux turning to ash","The torch flame size","Molten solder being drawn into the gap between tube and fitting"], correct:3, re:"A correctly sized joint gap lets capillary action pull the molten solder all the way around the fitting cup for a complete seal."},
  {id:37, block:1, sec:"Joining Methods", q:"Which joining method is performed on a wet or undrained copper line without draining it first?", opts:["Soldering","Brazing","Press fitting","Threading"], correct:2, re:"Press fittings can be made on lines that are not fully drained, unlike soldering, which requires the joint area to be dry."},
  {id:38, block:1, sec:"Joining Methods", q:"A no-hub coupling's stainless-steel clamps are tightened to:", opts:["A specified torque value with a calibrated wrench","Hand-tight only with no tool","Until the shield deforms fully","No particular value"], correct:0, re:"The bands are tightened to a manufacturer-specified torque (commonly 60 inch-pounds) so the gasket seals without over- or under-tightening."},
  {id:39, block:1, sec:"Joining Methods", q:"Brazing differs from soldering in that brazing:", opts:["Uses a lower-temperature filler metal","Uses solvent cement","Requires no heat","Uses a higher-temperature filler metal for stronger joints"], correct:3, re:"Brazing uses higher temperatures and filler metals that melt above about 840 F, producing stronger joints than soft soldering."},
  {id:40, block:1, sec:"Joining Methods", q:"Before soldering, the copper tube end and fitting socket should be:", opts:["Coated with paint","Soaked in primer","Cleaned bright with emery cloth or a fitting brush","Heated until red"], correct:2, re:"Cleaning the mating surfaces to bright metal removes oxide so flux and solder can bond properly and the joint will not leak."},
  {id:41, block:1, sec:"Fittings", q:"A union is installed in a pipe run mainly to:", opts:["Reduce the pipe diameter","Vent trapped air","Change flow direction 90 degrees","Allow the pipe to be disconnected without cutting"], correct:3, re:"A union lets a section of pipe be taken apart and reassembled for service without cutting, by unscrewing its central ring."},
  {id:42, block:1, sec:"Fittings", q:"A dielectric union is used to:", opts:["Speed up water flow","Add a cleanout","Reduce water pressure","Separate dissimilar metals to prevent galvanic corrosion"], correct:3, re:"A dielectric union electrically isolates copper from steel or galvanized pipe so galvanic corrosion does not eat away the joint."},
  {id:43, block:1, sec:"Fittings", q:"In DWV piping, a wye (Y) fitting is preferred over a sanitary tee on horizontal runs because it:", opts:["Is cheaper to buy","Needs no support","Has a larger opening","Joins the branch at about 45 degrees for smooth flow"], correct:3, re:"A wye brings the branch in at roughly 45 degrees, keeping waste moving smoothly so solids do not settle, which a sharp tee would cause on a horizontal line."},
  {id:44, block:1, sec:"Fittings", q:"A reducing coupling is used to:", opts:["Join two pipes of different diameters","Change flow direction","Cap the end of a line","Add a shutoff"], correct:0, re:"A reducing coupling connects a larger pipe to a smaller one in a straight run, transitioning between the two sizes."},
  {id:45, block:1, sec:"Fittings", q:"An elbow (ell) fitting is used to:", opts:["Join three pipes","Provide a cleanout","Reduce pressure","Change the direction of a pipe run"], correct:3, re:"Elbows change pipe direction, commonly by 90 or 45 degrees; long-sweep elbows give a gentler turn for drainage."},
  {id:46, block:1, sec:"Fittings", q:"A tee fitting is used to:", opts:["Cap a line","Join two equal pipes in a straight line","Create a branch connection from a main run","Take a run apart for service"], correct:2, re:"A tee provides a branch at 90 degrees to the main; a sanitary tee has a curved sweep for drainage flow."},
  {id:47, block:1, sec:"Fittings", q:"A bushing is a fitting used to:", opts:["Adapt a larger fitting opening down to a smaller pipe size","Change direction 45 degrees","Connect two hubless pipes","Provide a relief opening"], correct:0, re:"A bushing threads or fits into a larger opening to reduce it to a smaller size, taking up less room than a reducing coupling."},
  {id:48, block:1, sec:"Fittings", q:"A combination wye-and-eighth bend is used in drainage to:", opts:["Make a sharp 90-degree branch on a vertical stack","Reduce two sizes at once","Cap off a vent","Create a long-sweep change of direction for branch flow"], correct:3, re:"Pairing a 45-degree wye with a 1/8 bend forms a long, sweeping turn that lets a branch enter without choking the flow."},
  {id:49, block:1, sec:"Fittings", q:"A coupling (straight coupling) is used to:", opts:["Join two pipes of the same size end to end","Branch a line","Change direction","Reduce pressure"], correct:0, re:"A straight coupling connects two pipes of the same diameter in line; a slip or repair coupling can be slid over to mend a cut section."},
  {id:50, block:1, sec:"Fittings", q:"Which fitting permanently closes the end of a threaded pipe?", opts:["A cap","A union","A wye","A coupling"], correct:0, re:"A cap screws over the outside of a male pipe end to close it; a plug closes a female threaded opening from inside."},
  {id:51, block:1, sec:"Fittings", q:"On a horizontal drain, a cleanout fitting is best installed using a:", opts:["Wye (or combination wye) so a rod can pass with the flow","Sanitary tee turned on its back","Plain 90-degree ell","Plain straight coupling"], correct:0, re:"A wye lets a cleaning rod follow the direction of flow, so codes require a wye rather than a sanitary tee for a horizontal cleanout."},
  {id:52, block:1, sec:"Fittings", q:"A long-sweep (long-radius) elbow is preferred in drainage because it:", opts:["Turns the flow more gradually to keep waste moving","Saves space over a short elbow","Is required for venting only","Reduces the pipe size"], correct:0, re:"A long-sweep ell has a larger radius that turns waste gradually, reducing the chance of clogs compared with a short-radius elbow."},
  {id:53, block:1, sec:"Fittings", q:"A street fitting (street ell, for example) has:", opts:["Two female ends","Three openings","One male and one female end","A built-in valve"], correct:2, re:"A street fitting has one male (spigot) end and one female (hub) end, so it can join directly into another fitting without a short nipple."},
  {id:54, block:1, sec:"Fittings", q:"When copper tube must connect to a galvanized steel pipe, the code-preferred fitting is a:", opts:["Plain brass coupling","Flared joint","Solvent-cement socket","Dielectric union or dielectric fitting"], correct:3, re:"A dielectric fitting separates the dissimilar metals, preventing the galvanic corrosion that would otherwise attack the copper-to-steel connection."},
  {id:55, block:1, sec:"Fittings", q:"A trap adapter fitting is used to:", opts:["Connect a fixture's tubular trap to the drain pipe","Reduce water pressure","Vent the stack","Join two cast iron hubs"], correct:0, re:"A trap adapter transitions from the thin-wall tubular trap of a fixture to the standard DWV drain pipe with a slip-nut and washer."},
  {id:56, block:1, sec:"Fittings", q:"A closet flange (toilet flange) serves to:", opts:["Regulate tank pressure","Reduce the drain size","Vent the bathroom","Anchor the toilet and connect it to the drain"], correct:3, re:"The closet flange fastens to the floor and the drain pipe, providing the seal surface and bolt anchorage for the water closet."},
  {id:57, block:1, sec:"Fittings", q:"Why should the number of fittings in a water line be kept reasonable?", opts:["Fittings add cost only","Fittings reduce pipe strength to zero","Each fitting adds friction loss and a potential leak point","Fittings are never code-approved"], correct:2, re:"Every fitting adds friction (pressure loss) and another joint that could leak, so runs are planned to use only the fittings needed."},
  {id:58, block:1, sec:"Fittings", q:"A reducer in a horizontal drain line is typically installed as an eccentric reducer to:", opts:["Keep the tops level so solids do not pond","Increase the slope sharply","Add a vent","Allow threading"], correct:0, re:"An eccentric reducer keeps one side (the invert) in line so the horizontal drain does not form a pocket where solids and water could collect."},
  {id:59, block:1, sec:"Fittings", q:"A no-hub coupling differs from a threaded union because it:", opts:["Seals dissimilar metals electrically","Requires solvent cement","Is used only on PEX","Joins hubless cast iron with a gasketed clamping band"], correct:3, re:"A no-hub coupling clamps a gasket over plain (hubless) cast iron pipe ends, while a union is a threaded take-apart joint for metal pipe."},
  {id:60, block:1, sec:"Fittings", q:"A plug is used to:", opts:["Close a female threaded opening","Close a male pipe end","Branch a line at 45 degrees","Reduce two pipe sizes"], correct:0, re:"A plug screws into a female threaded opening or fitting to close it, whereas a cap fits over a male end."},
  {id:61, block:1, sec:"Valves", q:"A gate valve is best suited for service that is:", opts:["Frequent throttling of flow","Reducing system pressure","Preventing backflow only","Fully open or fully closed (isolation)"], correct:3, re:"A gate valve raises a wedge clear of the bore when open and is meant for on/off isolation, not for throttling, where it can chatter and erode."},
  {id:62, block:1, sec:"Valves", q:"A globe valve is designed mainly to:", opts:["Throttle and regulate flow","Provide a quarter-turn shutoff","Prevent reverse flow","Relieve excess pressure"], correct:0, re:"A globe valve forces flow through a seat in a Z-path, giving good throttling control at the cost of a higher pressure drop than a gate or ball valve."},
  {id:63, block:1, sec:"Valves", q:"A ball valve is operated by:", opts:["Many turns of a handwheel","A float","A quarter (90-degree) turn of the handle","Thermal expansion"], correct:2, re:"A ball valve uses a bored ball that opens or closes with a quarter turn, giving fast, reliable on/off control with low pressure drop."},
  {id:64, block:1, sec:"Valves", q:"A check valve is installed to:", opts:["Throttle flow","Strain debris","Reduce pressure to 80 psi","Allow flow in one direction and prevent reverse flow"], correct:3, re:"A check valve permits flow one way and closes against reverse flow, helping prevent backflow and protecting equipment such as pumps."},
  {id:65, block:1, sec:"Valves", q:"A pressure-reducing valve (PRV) on a water service is used to:", opts:["Boost low incoming pressure","Lower high incoming pressure to a safe set point","Prevent backflow","Drain the system"], correct:1, re:"A PRV automatically reduces high street pressure to a lower set value (commonly 80 psi or less) to protect the building piping and fixtures."},
  {id:66, block:1, sec:"Valves", q:"An angle stop (fixture supply stop) is installed to:", opts:["Shut off water to a single fixture for service","Reduce pressure for the whole house","Prevent water hammer everywhere","Vent the fixture drain"], correct:0, re:"An angle stop lets one fixture, such as a faucet or toilet, be isolated for repair without shutting down the whole building's water."},
  {id:67, block:1, sec:"Valves", q:"Why is a gate valve a poor choice for throttling flow?", opts:["It cannot fully close","It has no handle","Partial opening causes vibration and seat erosion","It only fits plastic pipe"], correct:2, re:"Held partly open, a gate's disc vibrates in the flow and the seat erodes, so gates are used fully open or fully closed."},
  {id:68, block:1, sec:"Valves", q:"A typical residential angle stop has an outlet of:", opts:["3/8-inch compression","2-inch threaded","4-inch hub","1-inch sweat only"], correct:0, re:"Most fixture angle stops have a 3/8-inch compression outlet that connects to the faucet or toilet supply riser."},
  {id:69, block:1, sec:"Valves", q:"A hose bibb (sillcock) that supplies a garden hose should be fitted with:", opts:["A pressure regulator","A second check on the meter","A hose-connection vacuum breaker","A larger handle"], correct:2, re:"A hose-connection vacuum breaker prevents contaminated water from being back-siphoned through the hose into the potable supply."},
  {id:70, block:1, sec:"Valves", q:"In a swing check valve, the closure element is a:", opts:["Sliding wedge","Hinged disc that swings shut against reverse flow","Rotating ball","Diaphragm pushed by a spring only"], correct:1, re:"A swing check has a hinged disc that opens with forward flow and swings closed when flow reverses."},
  {id:71, block:1, sec:"Valves", q:"The main shutoff valve on a building water service exists primarily to:", opts:["Reduce pressure","Isolate the whole building's water for repairs or emergencies","Heat the water","Vent the system"], correct:1, re:"A full-open main shutoff lets the entire building's supply be turned off for maintenance or in an emergency such as a burst pipe."},
  {id:72, block:1, sec:"Valves", q:"Compared with a gate valve, a ball valve generally offers:", opts:["Slower operation","Better fine throttling","Faster on/off operation and reliable sealing after long idle periods","No pressure rating"], correct:2, re:"Ball valves close in a quarter turn and tend to seal reliably even after sitting unused, which is why they are widely used for shutoff."},
  {id:73, block:1, sec:"Valves", q:"When a pressure-reducing valve creates a closed system, the installation also needs:", opts:["A second meter","A thermal-expansion tank","A larger drain","No additional device"], correct:1, re:"Behind a PRV (or check), water cannot expand back into the main, so a thermal-expansion tank is added to absorb the increased pressure from heating."},
  {id:74, block:1, sec:"Valves", q:"A water-hammer arrestor is a device that:", opts:["Increases static pressure","Cushions the shock when a quick-closing valve stops the flow","Filters sediment","Prevents freezing"], correct:1, re:"An arrestor contains an air chamber or piston that absorbs the surge created when a fast-closing valve abruptly stops moving water, reducing banging pipes."},
  {id:75, block:1, sec:"Valves", q:"Which valve type has the lowest pressure drop when fully open?", opts:["Globe valve","Gate or full-port ball valve","Angle globe valve","Foot valve"], correct:1, re:"A fully open gate or full-port ball valve leaves a nearly clear bore, giving very little flow resistance compared with a globe valve's Z-path."},
  {id:76, block:1, sec:"Valves", q:"A relief valve on a closed water system differs from a shutoff valve because it:", opts:["Is operated by hand","Throttles flow continuously","Opens automatically to relieve excess pressure","Only stops reverse flow"], correct:2, re:"A relief valve is spring-loaded to open by itself when pressure (or temperature) exceeds a set limit, protecting the system from rupture."},
  {id:77, block:1, sec:"Valves", q:"A foot valve at the bottom of a pump suction line is a type of:", opts:["Pressure regulator","Check valve that keeps the line primed","Gate valve","Globe valve"], correct:1, re:"A foot valve is a check valve with a strainer that holds water (prime) in the suction line so the pump does not lose its prime."},
  {id:78, block:1, sec:"Valves", q:"On a faucet, the hot and cold supply stops are conventionally arranged so that, facing the fixture:", opts:["Hot is on the left, cold on the right","Both are on the right","Hot is on the right, cold on the left","Position does not matter"], correct:0, re:"By long-standing convention hot is on the left and cold on the right at the fixture, matching what users expect."},
  {id:79, block:1, sec:"Valves", q:"A quarter-turn angle stop is usually built as a:", opts:["Multi-turn globe stop","Ball-type valve","Diaphragm valve","Gate valve"], correct:1, re:"Modern quarter-turn angle stops use a small ball valve, which is quicker and tends to seize less than the older multi-turn compression stops."},
  {id:80, block:1, sec:"Valves", q:"The main reason to install individual fixture stops throughout a building is to:", opts:["Increase overall pressure","Allow each fixture to be serviced without shutting off the whole building","Eliminate the need for a main valve","Reduce the pipe size"], correct:1, re:"Fixture stops let a single faucet, toilet, or appliance be isolated for repair while the rest of the building keeps water service."},
  {id:81, block:1, sec:"Insulation & Supports", q:"Horizontal Schedule 40 PVC and ABS DWV pipe is commonly required to be supported at intervals of about:", opts:["4 feet","12 feet","20 feet","No support is required"], correct:0, re:"Plastic DWV pipe sags between supports, so codes commonly require horizontal support roughly every 4 feet for any diameter."},
  {id:82, block:1, sec:"Insulation & Supports", q:"A pipe hanger or strap should be made of a material that:", opts:["Is always steel regardless of pipe","Is as small as possible","Is compatible with the pipe to avoid corrosion","Conducts electricity well"], correct:2, re:"Supports must be compatible with the pipe (for example, not bare steel directly on copper) so a galvanic or chemical reaction does not corrode the pipe."},
  {id:83, block:1, sec:"Insulation & Supports", q:"Pipe insulation on a hot-water line primarily serves to:", opts:["Increase water pressure","Reduce heat loss and save energy","Add structural support","Prevent backflow"], correct:1, re:"Insulating hot-water pipe slows heat loss, so water arrives hotter and the water heater uses less energy."},
  {id:84, block:1, sec:"Insulation & Supports", q:"Insulating a cold-water pipe in a humid area mainly helps to:", opts:["Boost flow rate","Control condensation (sweating) on the pipe","Raise water temperature","Increase pressure"], correct:1, re:"Cold pipe surfaces below the dew point sweat; closed-cell insulation with a vapor barrier keeps moisture from condensing and dripping."},
  {id:85, block:1, sec:"Insulation & Supports", q:"Pipe insulation is used in unheated areas chiefly to:", opts:["Speed up drainage","Slow heat loss and reduce the risk of freezing","Add color coding","Replace pipe supports"], correct:1, re:"Insulation cannot guarantee a pipe will not freeze, but it slows heat loss and lengthens the time before standing water can freeze and burst the pipe."},
  {id:86, block:1, sec:"Insulation & Supports", q:"Where bare copper tube would otherwise rest on a steel support, good practice is to:", opts:["Bond them together","Solder them together","Isolate the copper from the steel with a compatible or coated hanger","Leave the copper unsupported"], correct:2, re:"Separating copper from dissimilar metal supports with a plastic-coated or copper-compatible hanger prevents galvanic corrosion at the contact point."},
  {id:87, block:1, sec:"Insulation & Supports", q:"Horizontal hubless cast iron soil pipe is generally supported:", opts:["Only at the building ends","At or near each joint (and within a limited spacing)","Every 20 feet","Never, because it is rigid"], correct:1, re:"Heavy cast iron and its gasketed joints are supported at or near each hub/joint and within a limited spacing so the joints are not stressed."},
  {id:88, block:1, sec:"Insulation & Supports", q:"Compared with rigid metal pipe, plastic pipe generally needs:", opts:["Wider support spacing","Closer support spacing because it is more flexible","No support at all","Support only when vertical"], correct:1, re:"Plastic pipe is more flexible and sags more, so it requires closer hanger spacing than the same size of rigid metal pipe."},
  {id:89, block:1, sec:"Insulation & Supports", q:"Vertical piping in a multistory run is typically supported:", opts:["Only at the very top","At each floor or within a limited vertical interval","Never","Only at the base"], correct:1, re:"Vertical pipe is supported at floor lines or within a code interval (commonly not exceeding about 10 feet) so its weight is carried at intervals, not all at the bottom."},
  {id:90, block:1, sec:"Insulation & Supports", q:"Flexible PEX tubing run horizontally generally needs support:", opts:["At wider spacing than rigid copper","At closer spacing than rigid copper because it is flexible","Only at the manifold","Never"], correct:1, re:"Because PEX is flexible and sags readily, it is supported at closer intervals than rigid copper (often around 32 inches horizontally)."},
  {id:91, block:1, sec:"Insulation & Supports", q:"A pipe support's main job is to:", opts:["Reduce water pressure","Carry the weight of the pipe and contents and maintain proper grade","Prevent backflow","Insulate the pipe"], correct:1, re:"Supports hold up the pipe and its water so it does not sag, keeping drainage pipe at its required slope and preventing stress on joints."},
  {id:92, block:1, sec:"Insulation & Supports", q:"Closed-cell elastomeric foam is a popular pipe insulation because it:", opts:["Conducts heat well","Resists moisture and works on both hot and cold lines","Is a structural support","Only fits cast iron"], correct:1, re:"Closed-cell foam resists water absorption, making it suitable for cold lines (condensation control) and hot lines (heat retention) alike."},
  {id:93, block:1, sec:"Insulation & Supports", q:"Where a plastic drain pipe passes through a metal stud or strap, an installer should:", opts:["Wedge it tightly so it cannot move at all","Allow for expansion and protect the pipe from abrasion","Solder the contact point","Remove the support"], correct:1, re:"Plastic pipe expands and contracts with temperature, so supports should let it move and protect it from chafing on metal edges."},
  {id:94, block:1, sec:"Insulation & Supports", q:"Adequate support of a horizontal drain line is important mainly because sagging can:", opts:["Increase water pressure","Create low spots (bellies) where waste collects","Improve venting","Reduce the pipe size"], correct:1, re:"A sag forms a belly that holds water and solids, leading to stoppages, so drains must be supported to keep a continuous slope."},
  {id:95, block:1, sec:"Insulation & Supports", q:"Insulating both hot and cold pipes in a wall can also help by:", opts:["Increasing water hammer","Reducing noise from water flowing in the pipes","Raising static pressure","Eliminating the need for valves"], correct:1, re:"Besides thermal benefits, pipe insulation can dampen the sound of flowing water and reduce noise transmitted through the structure."},
  {id:96, block:1, sec:"Materials Standards & Identification", q:"Copper water tube type is identified on the job by a color stripe; Type K is marked:", opts:["Red","Blue","Green","Yellow"], correct:2, re:"By the standard color code, Type K is green, Type L is blue, and Type M is red, printed along the length of the tube."},
  {id:97, block:1, sec:"Materials Standards & Identification", q:"Type L copper tube carries which identification color?", opts:["Blue","Green","Red","Black"], correct:0, re:"Type L is color-coded blue; Type K is green and Type M is red under the common copper-tube marking system."},
  {id:98, block:1, sec:"Materials Standards & Identification", q:"All pipe, solder, and fittings on a potable-water system must be:", opts:["Painted blue","At least 2 inches in size","Galvanized only","Lead-free"], correct:3, re:"Materials in contact with drinking water must meet lead-free limits to protect water quality, a requirement reinforced by federal and California law."},
  {id:99, block:1, sec:"Materials Standards & Identification", q:"PEX tubing sold in red and blue colors uses those colors to:", opts:["Indicate different pressure ratings","Identify hot versus cold lines for the installer","Show which is for gas","Mark thicker walls"], correct:1, re:"PEX color (red for hot, blue for cold, white for either) is only for identification; the color does not change the tubing's pressure or temperature rating."},
  {id:100, block:1, sec:"Materials Standards & Identification", q:"A neoprene gasket used in a no-hub cast iron coupling must meet:", opts:["A solder-purity standard","An elastomer standard such as ASTM C564","A copper-temper standard","A solvent-cement standard"], correct:1, re:"The neoprene gasket for hubless cast iron joints is specified to ASTM C564, ensuring it seals and resists the materials in the drainage system."},
  {id:101, block:2, sec:"Water Service & Meter", q:"The water service pipe is best defined as the piping that runs from:", opts:["The public main or source to the building water-distribution system","The water meter to the most remote fixture","The water heater to each fixture","Fixture to fixture inside a wall"], correct:0, re:"The water service is the pipe between the public main (or other source) and the point where the building distribution system begins, usually at or just inside the structure."},
  {id:102, block:2, sec:"Water Service & Meter", q:"A full-open valve required for a water meter must have an open area that is:", opts:["One-half the service area","At least equal to the cross-section of the water service","Twice the service area","Smaller than the service to throttle flow"], correct:1, re:"The meter valve must be a full-way (full-port) type whose open area is at least that of the water service so it does not restrict flow."},
  {id:103, block:2, sec:"Water Service & Meter", q:"The minimum earth cover normally required over a buried water service pipe is about:", opts:["3 inches","6 inches","12 inches","36 inches"], correct:2, re:"Codes generally require at least 12 inches of backfill cover over the top of a buried water service pipe to protect it."},
  {id:104, block:2, sec:"Water Service & Meter", q:"When the building sewer is not of approved pressure-rated material, the water service pipe must be separated from it horizontally by not less than:", opts:["1 foot","2 feet","20 feet","5 feet"], correct:3, re:"A water service must be at least 5 feet of undisturbed or compacted earth from an ordinary building sewer to reduce contamination risk."},
  {id:105, block:2, sec:"Water Service & Meter", q:"A water service may run closer than 5 feet to a building sewer only if the water pipe is placed:", opts:["At least 12 inches above the top of the sewer","Below the sewer","In the same trench at the same level","Made of cast iron"], correct:0, re:"The 5-foot separation can be reduced when the bottom of the water service is at least 12 inches above the highest point of the sewer."},
  {id:106, block:2, sec:"Water Service & Meter", q:"Where a water service pipe must cross a building sewer, the water pipe should be:", opts:["Left bare and touching the sewer","Sleeved or the joints kept well away from the crossing","Reduced one pipe size","Tied to the sewer for support"], correct:1, re:"At a crossing the water service is commonly sleeved or its joints kept clear of the sewer so a leak cannot draw in contamination."},
  {id:107, block:2, sec:"Water Service & Meter", q:"A drain (bleed) valve on the discharge side of an indoor meter valve is provided mainly to:", opts:["Raise pressure","Heat the meter","Allow the downstream piping to be drained","Vent gas"], correct:2, re:"A drain valve downstream of the meter lets the building piping be emptied for repairs or freeze protection."},
  {id:108, block:2, sec:"Water Service & Meter", q:"The main building shutoff (control) valve is normally located:", opts:["At the most remote fixture","On the roof","Inside the water heater","Near where the service enters the building or at the meter, readily accessible"], correct:3, re:"A readily accessible full-open control valve is installed near the meter or where the service enters, so the whole building can be shut off."},
  {id:109, block:2, sec:"Water Service & Meter", q:"A water meter primarily serves to:", opts:["Measure the volume of water used","Reduce water pressure","Prevent backflow","Filter sediment"], correct:0, re:"The meter records the quantity of water that passes into the building for billing; it is not a pressure or backflow device."},
  {id:110, block:2, sec:"Water Service & Meter", q:"Unions on the inlet and outlet of a water meter are provided so that the meter can be:", opts:["Pressurized higher","Removed or replaced without cutting pipe","Used as a shutoff","Buried deeper"], correct:1, re:"Unions let the meter be taken out and reinstalled for service or exchange without cutting into the piping."},
  {id:111, block:2, sec:"Water Service & Meter", q:"A water service that is too small for the building demand will most likely cause:", opts:["Excess pressure","Water hammer only","Inadequate flow and pressure drop at fixtures","Backflow"], correct:2, re:"An undersized service cannot carry the required flow, so pressure drops and fixtures starve when demand is high."},
  {id:112, block:2, sec:"Water Service & Meter", q:"The two main quantities needed to size a water service pipe are the available pressure and the:", opts:["Pipe color","Number of stories only","Cost of copper","Required flow (demand) the building must deliver"], correct:3, re:"Sizing balances the demand (flow needed) against the pressure available and the friction loss the pipe will impose."},
  {id:113, block:2, sec:"Water Service & Meter", q:"Galvanized steel water service pipe is generally discouraged today mainly because it:", opts:["Corrodes and restricts flow with mineral buildup over time","Is too flexible","Cannot be threaded","Is illegal everywhere"], correct:0, re:"Galvanized pipe rusts internally and clogs with scale, reducing flow; copper, PEX, or plastic are usually preferred."},
  {id:114, block:2, sec:"Water Service & Meter", q:"Before sizing the building supply, the plumber should first determine the:", opts:["Paint scheme","Static (no-flow) pressure available at the service","Number of cleanouts","Trap seal depth"], correct:1, re:"The available static pressure at the source is the starting point; from it the designer subtracts elevation and friction losses."},
  {id:115, block:2, sec:"Water Service & Meter", q:"A pressure gauge attached at a hose bibb with no water flowing reads the system's:", opts:["Residual pressure","Flow velocity","Static pressure","Friction loss"], correct:2, re:"With no fixtures open, the gauge shows static pressure; once water flows, the lower reading is the residual pressure."},
  {id:116, block:2, sec:"Water Service & Meter", q:"The water-distribution system inside a building begins:", opts:["At the city reservoir","At each faucet","At the water heater outlet","Where the water service ends, typically at the meter or main shutoff"], correct:3, re:"Distribution piping is the network downstream of the service that carries water to fixtures and appliances throughout the building."},
  {id:117, block:2, sec:"Water Service & Meter", q:"A corporation stop and curb stop are valves associated with the:", opts:["Connection of the service to the public main and at the property line","Water heater","Vent system","Trap arm"], correct:0, re:"The corporation stop taps the main and the curb stop sits near the property line, both on the water service ahead of the meter."},
  {id:118, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"When static water pressure in the supply piping exceeds 80 psi, the code requires:", opts:["A larger meter","An approved pressure regulator to reduce it to 80 psi or less","A second water service","No action below 100 psi"], correct:1, re:"Above 80 psi static, an approved pressure-reducing valve preceded by a strainer must lower the pressure to 80 psi or less."},
  {id:119, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"A pressure-reducing valve (PRV) on a water service is normally preceded by:", opts:["A check valve only","A second PRV","An adequate strainer","A vacuum breaker"], correct:2, re:"An adequate strainer ahead of the regulator keeps debris from fouling the valve seat, though larger regulators may be exempt from a separate strainer."},
  {id:120, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"Pressure regulators for a potable water-distribution system are required to comply with:", opts:["ASSE 1010","NSF for drains","No standard","ASSE 1003 (or AWWA C530)"], correct:3, re:"Potable-water pressure regulators must meet ASSE 1003 or AWWA C530 so they perform reliably and safely."},
  {id:121, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"Installing a PRV typically converts the building piping into a:", opts:["Closed system in which thermal expansion can raise pressure","Vented open system","Gravity drain","Low-hazard system needing no relief"], correct:0, re:"A PRV acts as a one-way restriction, so expanded hot water cannot push back to the main and an expansion control device is needed."},
  {id:122, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"A common reason to limit building water pressure to about 80 psi is that higher pressure:", opts:["Saves water","Stresses joints and fixtures and worsens water hammer","Improves drainage","Has no drawbacks"], correct:1, re:"Excess pressure strains valves, fittings, hoses, and appliances, increases leaks, and intensifies water-hammer shock."},
  {id:123, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"Residual (flowing) pressure differs from static pressure in that residual pressure is measured:", opts:["With all valves closed","Only at the meter","While water is actually flowing","At the city main"], correct:2, re:"Static pressure is the no-flow reading; residual pressure is what remains at a fixture while water is being drawn, after friction losses."},
  {id:124, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"If the source cannot keep at least roughly 15 psi residual at the highest fixture, the system must add:", opts:["A larger trap","More cleanouts","A second vent","A water tank with a pump or other means to boost pressure"], correct:3, re:"When street pressure is too low to maintain about 15 psi at the top fixtures, a booster pump or tank system is required."},
  {id:125, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"For fixtures supplied by flush tanks, the minimum flowing pressure commonly needed is about:", opts:["8 psi","30 psi","60 psi","80 psi"], correct:0, re:"Ordinary flush-tank fixtures generally need only about 8 psi flowing, whereas flushometer valves need roughly 15 psi or more."},
  {id:126, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"A flushometer (direct-flush) valve typically requires a minimum flowing pressure of at least about:", opts:["3 psi","15 psi","8 psi","2 psi"], correct:1, re:"Flushometer valves move a large flow quickly and usually require about 15 psi or more flowing to operate correctly."},
  {id:127, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"For every foot of vertical rise, static water pressure in a column drops by about:", opts:["0.10 psi","1.0 psi","0.43 psi","2.31 psi"], correct:2, re:"Water loses about 0.43 psi per foot of height (it takes 2.31 feet of head to make 1 psi), so taller buildings see lower pressure upstairs."},
  {id:128, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"A 50-foot rise in elevation reduces static pressure by approximately:", opts:["About 5 psi","About 50 psi","About 100 psi","About 22 psi"], correct:3, re:"At roughly 0.43 psi per foot, 50 feet of lift removes about 21 to 22 psi of static pressure from the supply."},
  {id:129, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"A PRV is typically adjusted by:", opts:["Turning an adjusting screw that sets the spring tension","Replacing the spring with copper","Heating the body","Adding a larger strainer"], correct:0, re:"Turning the adjusting screw changes the spring force on the diaphragm, setting the reduced downstream pressure."},
  {id:130, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"Most pressure-reducing valves used in homes are set to deliver a downstream pressure in the range of about:", opts:["5 to 10 psi","45 to 60 psi","90 to 110 psi","120 to 150 psi"], correct:1, re:"PRVs are commonly set near 45 to 60 psi, comfortably below the 80 psi limit while still giving good fixture performance."},
  {id:131, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"A failing or stuck-open PRV most often shows up as:", opts:["No water at all","Cold water turning hot","Downstream pressure climbing back toward main pressure","A blocked vent"], correct:2, re:"If a PRV fails open or its diaphragm tears, downstream pressure rises toward full main pressure and may exceed 80 psi."},
  {id:132, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"Excessively high household pressure most commonly damages appliances such as:", opts:["Light fixtures","Floor drains","Roof vents","Dishwashers, washing machines, and water heaters"], correct:3, re:"Water-using appliances and their fill valves and hoses are stressed by high pressure, which shortens their life and causes leaks."},
  {id:133, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"The strainer ahead of a PRV is there mainly to:", opts:["Catch grit and debris that could lodge in the valve seat","Reduce pressure","Add chlorine","Measure flow"], correct:0, re:"Sediment can hold the regulator seat open or cause it to creep; the strainer captures debris to keep the PRV working."},
  {id:134, block:2, sec:"Pressure & Pressure-Reducing Valves", q:"A pressure regulator that is 1-1/2 inches or larger generally:", opts:["Must always have two strainers","Does not require a separate strainer","Cannot be used on potable water","Must be installed upside down"], correct:1, re:"Codes commonly exempt regulators of 1-1/2 inches and larger from the separate strainer requirement because of their construction and flow."},
  {id:135, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"The load that fixtures place on a water-supply pipe is expressed in:", opts:["Drainage fixture units (DFU)","BTU","Water-supply fixture units (WSFU)","Decibels"], correct:2, re:"Water-supply demand is tallied in water-supply fixture units (WSFU), which are then converted to a probable peak flow in gpm."},
  {id:136, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"Total fixture units are converted to a probable peak demand in gallons per minute using:", opts:["Ohm's law","The trap-seal chart","The slope formula","A demand table or Hunter's curve"], correct:3, re:"A demand table (Hunter's curve) gives the probable simultaneous flow in gpm for a given number of fixture units."},
  {id:137, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"The demand in gpm corresponding to a number of fixture units is higher when water closets are served by:", opts:["Flushometer (direct-flush) valves","Flush tanks","Hose bibbs","Floor drains"], correct:0, re:"Flushometer valves draw a large instantaneous flow, so for the same fixture-unit count the probable demand in gpm is greater than with flush tanks."},
  {id:138, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"For a fixture with both hot and cold connections, each separate hot and cold fixture-unit value may be taken as about:", opts:["The full listed total","Three-quarters of the listed total","Twice the listed total","Zero"], correct:1, re:"Because hot and cold are not used at full rate simultaneously, each branch is commonly counted as three-quarters of the listed total fixture units."},
  {id:139, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"Friction loss in a water pipe increases when the:", opts:["Pipe diameter increases","Water gets colder only","Flow velocity increases or the pipe is longer","Pressure is reduced"], correct:2, re:"Friction loss rises with higher velocity, longer runs, smaller diameter, and rougher pipe, consuming available pressure."},
  {id:140, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"To limit noise and erosion-corrosion, cold-water velocity in copper tube is usually kept at or below about:", opts:["2 fps","20 fps","40 fps","8 fps"], correct:3, re:"Designers commonly cap cold-water velocity near 8 fps in copper to avoid noise and erosion of the tube wall."},
  {id:141, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"Hot-water velocity in copper tube is generally held lower than cold water, to about:", opts:["5 fps","8 fps","15 fps","25 fps"], correct:0, re:"Hot water is more aggressive, so velocity in copper is usually limited to about 5 fps to reduce erosion-corrosion."},
  {id:142, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"For the same flow rate, a smaller-diameter pipe will have:", opts:["Lower velocity and less friction loss","Higher velocity and greater friction loss","No change in friction","Lower noise"], correct:1, re:"Reducing diameter forces the same flow through a smaller area, raising velocity and friction loss sharply."},
  {id:143, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"The 'developed length' used in sizing a water pipe means the:", opts:["Straight-line distance only","Pipe diameter","Total measured run plus allowances for fittings and valves","Vertical rise only"], correct:2, re:"Developed length is the actual pipe run plus equivalent length added for fittings and valves, used to total the friction loss."},
  {id:144, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"In a typical sizing problem, the pressure available to overcome pipe friction equals the source pressure minus:", opts:["Only the meter cost","The pipe color","The number of fixtures","Elevation (static) loss, fixture pressure needed, and device losses"], correct:3, re:"From the source pressure you subtract elevation loss, the minimum pressure required at the fixture, and meter/regulator/backflow losses; the remainder is available for friction."},
  {id:145, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"Adding many elbows and fittings to a run mainly affects sizing by:", opts:["Increasing the equivalent length and thus friction loss","Lowering the demand","Reducing velocity","Raising static pressure"], correct:0, re:"Each fitting adds equivalent length; many fittings raise total friction loss, which may require a larger pipe."},
  {id:146, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"A hose bibb counted for sizing is generally assigned fixture units because it:", opts:["Never uses water","Can draw a substantial continuous flow","Is always closed","Reduces demand"], correct:1, re:"A hose bibb can draw a high, sustained flow, so it carries fixture units; additional hose bibbs on the same pipe may be counted at a reduced rate."},
  {id:147, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"A continuous-flow demand, such as for an irrigation supply, is handled in sizing by:", opts:["Ignoring it","Halving the pipe size","Adding its gpm separately to the fixture-unit demand","Counting it as one fixture unit"], correct:2, re:"Continuous flows do not follow the intermittent fixture-unit model, so their gpm is added directly to the demand for the affected piping."},
  {id:148, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"Compared with a long run, a short run of the same pipe at the same flow will have:", opts:["More friction loss","The same total loss","No velocity","Less total friction loss"], correct:3, re:"Friction loss is proportional to length, so a shorter run of identical pipe and flow loses less pressure to friction."},
  {id:149, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"Sizing the water distribution so each fixture gets adequate flow during peak use is important because:", opts:["Multiple fixtures may operate at once and compete for flow","It lowers the water bill","All pipes must match","It removes the need for a meter"], correct:0, re:"Pipe must carry the probable simultaneous demand so that opening one fixture does not starve another during busy periods."},
  {id:150, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"Oversizing water-distribution pipe well beyond the demand can cause:", opts:["Better hot-water delivery","Long waits for hot water and wasted water and energy","Lower friction problems only","Higher pressure at fixtures"], correct:1, re:"Excessively large hot-water pipe holds more cooled water, so users wait longer and waste water and energy while it clears."},
  {id:151, block:2, sec:"Pipe Sizing, Demand & Friction Loss", q:"The probable (design) demand on a building supply is normally less than the sum of all fixture flows because:", opts:["Fixtures never run","The meter blocks flow","Not all fixtures are used at the same instant","Pressure is unlimited"], correct:2, re:"Fixture-unit methods account for the low likelihood that every fixture runs simultaneously, so design demand is below the arithmetic total."},
  {id:152, block:2, sec:"Water Hammer & Arrestors", q:"Water hammer is the banging or shock that occurs when:", opts:["A pipe is too large","Pressure is too low","A trap is too deep","A quick-closing valve suddenly stops moving water"], correct:3, re:"Stopping a moving column of water abruptly converts its momentum into a pressure surge that shocks and shakes the piping."},
  {id:153, block:2, sec:"Water Hammer & Arrestors", q:"A water-hammer arrestor controls the surge by:", opts:["Providing a sealed air cushion that absorbs the shock","Filtering the water","Increasing static pressure","Heating the pipe"], correct:0, re:"The arrestor contains a permanently sealed air chamber or piston that compresses to absorb the pressure spike."},
  {id:154, block:2, sec:"Water Hammer & Arrestors", q:"The code requires water-hammer protection wherever the system has:", opts:["Only flush tanks","Quick-acting (quick-closing) valves","No appliances","Galvanized pipe"], correct:1, re:"Systems with quick-acting valves must have approved devices to absorb the hammer those valves produce on closing."},
  {id:155, block:2, sec:"Water Hammer & Arrestors", q:"Manufactured water-hammer arrestors must comply with:", opts:["ASSE 1003 only","NSF 14 only","ASSE 1010 or PDI-WH 201","No standard"], correct:2, re:"Approved arrestors conform to ASSE 1010 or PDI-WH 201, which set performance and durability requirements."},
  {id:156, block:2, sec:"Water Hammer & Arrestors", q:"A water-hammer arrestor should be installed:", opts:["As far as possible from the valve","Only at the meter","On the vent stack","As close as possible to the quick-closing valve"], correct:3, re:"Placing the arrestor close to the quick-closing valve lets it absorb the surge before it travels through the piping."},
  {id:157, block:2, sec:"Water Hammer & Arrestors", q:"A common cause of sudden water hammer at a laundry is the:", opts:["Solenoid (quick-closing) valve in a washing machine","Floor drain","Trap vent","Water meter"], correct:0, re:"The washer's solenoid valves snap shut quickly, so hammer arrestors are commonly fitted on its hot and cold supplies."},
  {id:158, block:2, sec:"Water Hammer & Arrestors", q:"A dishwasher, which also uses a fast-closing fill valve, is best protected with an arrestor on:", opts:["The drain line","Its hot-water supply","The vent","The gas line"], correct:1, re:"A dishwasher draws hot water through a quick-closing valve, so an arrestor on its hot supply absorbs the resulting shock."},
  {id:159, block:2, sec:"Water Hammer & Arrestors", q:"Old-style air chambers (capped vertical stub pipes) eventually stop working because they:", opts:["Rust shut","Grow too long","Become waterlogged as the trapped air dissolves into the water","Freeze permanently"], correct:2, re:"The air in a plain stub gradually dissolves into the water and the chamber fills, so modern sealed arrestors are preferred."},
  {id:160, block:2, sec:"Water Hammer & Arrestors", q:"A mechanical (piston-type) arrestor is preferred over a plain air chamber because it:", opts:["Costs nothing","Needs no support","Raises pressure","Keeps its air charge sealed and does not become waterlogged"], correct:3, re:"The sealed piston or bellows keeps air separated from the water, so the device keeps absorbing shock for the long term."},
  {id:161, block:2, sec:"Water Hammer & Arrestors", q:"Besides arrestors, water hammer can be reduced by:", opts:["Lowering excessive pressure and securing loose pipes","Increasing velocity","Removing all valves","Adding more elbows"], correct:0, re:"Lower pressure and slower velocity weaken the surge, and securely strapped pipe transmits less noise and movement."},
  {id:162, block:2, sec:"Water Hammer & Arrestors", q:"Higher water velocity in a pipe tends to make water hammer:", opts:["Weaker","Stronger when a valve closes","Disappear","Unrelated to velocity"], correct:1, re:"The faster the moving column, the more momentum must be stopped, so a quick closure produces a larger pressure surge."},
  {id:163, block:2, sec:"Water Hammer & Arrestors", q:"Loose, unsecured water piping makes water hammer worse mainly because the pipe:", opts:["Leaks more","Gets hotter","Can move and bang against framing when the surge hits","Changes size"], correct:2, re:"Unsupported pipe whips and strikes structure during a surge; proper strapping limits movement and noise."},
  {id:164, block:2, sec:"Water Hammer & Arrestors", q:"A 'AA' or 'A' size arrestor per PDI-WH 201 is typically intended for:", opts:["An entire high-rise riser","A fire pump","A sewer line","A single residential fixture or appliance"], correct:3, re:"PDI sizes such as AA and A are sized by fixture units for individual residential connections like a washer or dishwasher."},
  {id:165, block:2, sec:"Water Hammer & Arrestors", q:"An accessible location is important for a water-hammer arrestor so it can be:", opts:["Inspected or replaced if it fails","Painted","Used as a shutoff","Heated"], correct:0, re:"Arrestors can lose effectiveness over time, so access allows them to be serviced or replaced when needed."},
  {id:166, block:2, sec:"Water Hammer & Arrestors", q:"Quick-closing valves include all of the following EXCEPT:", opts:["A washing-machine solenoid valve","A slowly turned gate valve","A dishwasher fill valve","An electric solenoid on an ice maker"], correct:1, re:"A gate valve closed slowly by hand does not snap shut, so it is not the quick-closing type that produces severe hammer."},
  {id:167, block:2, sec:"Water Hammer & Arrestors", q:"If banging pipes persist after a single arrestor is added, a likely remaining cause is:", opts:["The water is too clean","Too many cleanouts","Excessive system pressure or unsecured piping elsewhere","A deep trap seal"], correct:2, re:"Hammer often has multiple sources; high pressure and loose pipe runs can keep causing noise even after one arrestor is installed."},
  {id:168, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"The developed length of hot-water piping from the source to a fixture is generally limited to about:", opts:["10 feet","200 feet","No limit","50 feet"], correct:3, re:"Codes commonly cap the developed length of hot-water pipe to a fixture at about 50 feet, or a recirculation/heat-trace system must be provided."},
  {id:169, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"A hot-water recirculation loop is used mainly to:", opts:["Keep hot water near fixtures so users wait less and waste less","Raise water pressure","Filter the water","Prevent backflow"], correct:0, re:"Recirculation keeps heated water moving near the fixtures so hot water arrives quickly instead of running cold water down the drain."},
  {id:170, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"In a recirculation system, the recirculating piping is considered a:", opts:["Drain line","Source of hot or tempered water for measuring the 50-foot limit","Vent","Cold-water branch"], correct:1, re:"Because the loop delivers hot water near the fixtures, it counts as the source from which the maximum developed length is measured."},
  {id:171, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"To save energy, hot-water and recirculation piping is generally required to be:", opts:["Buried in concrete","Painted red","Insulated","Left bare for inspection"], correct:2, re:"Insulating the hot-water and recirculation piping reduces standby heat loss, as required by the energy code."},
  {id:172, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"To reduce scald risk, hot water delivered to bathtubs and showers is commonly limited to a maximum of about:", opts:["100°F","160°F","180°F","120°F"], correct:3, re:"About 120°F is the common maximum delivered temperature for showers and tubs to reduce the risk of scalding."},
  {id:173, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"A thermostatic (tempering) mixing valve at the water heater is used to:", opts:["Blend hot and cold to deliver water at a safer set temperature","Boost pressure","Prevent backflow","Drain the tank"], correct:0, re:"An ASSE 1017 tempering valve mixes hot tank water with cold to a controlled lower temperature for the distribution system."},
  {id:174, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"Storing water hotter than the delivery temperature and tempering it down is often done to:", opts:["Waste energy","Limit Legionella growth while still delivering safe temperatures","Lower pressure","Increase flow"], correct:1, re:"Higher storage temperature discourages Legionella bacteria, while a mixing valve tempers the delivered water back to a safe level."},
  {id:175, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"Thermal expansion occurs in a water heater because heated water:", opts:["Contracts","Becomes denser","Expands and increases in volume","Loses pressure"], correct:2, re:"Water expands as it is heated; in a closed system that added volume has nowhere to go, so pressure climbs."},
  {id:176, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"Water heated from about 50°F to 120°F expands by roughly:", opts:["0.02% (almost none)","20% in volume","50% in volume","2% in volume"], correct:3, re:"Heating water from about 50°F to 120°F increases its volume by roughly 2 percent, which raises pressure in a closed system."},
  {id:177, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"An expansion tank is required on a water heater whenever the system is:", opts:["Closed by a check valve, PRV, or backflow preventer","Open to the atmosphere","On a well only","Made of plastic"], correct:0, re:"A check valve, pressure regulator, or backflow device makes the system closed, so an expansion tank or device is required to absorb thermal expansion."},
  {id:178, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"A thermal-expansion tank is normally connected to the:", opts:["Hot-water outlet far from the heater","Cold-water supply piping to the water heater","Drain line","Vent stack"], correct:1, re:"The expansion tank is installed on the cold-water supply to the heater, downstream of any check valve, PRV, or backflow preventer."},
  {id:179, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"A diaphragm expansion tank absorbs expansion using:", opts:["A heating coil","A check valve","A pre-charged air cushion behind a flexible diaphragm","A filter screen"], correct:2, re:"As water expands it pushes against the diaphragm and compresses the captive air, holding pressure within safe limits."},
  {id:180, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"For best performance, the air pre-charge of an expansion tank should be set to:", opts:["Zero","Twice the system pressure","150 psi always","The static (no-flow) water pressure of the system"], correct:3, re:"Matching the pre-charge to the system static pressure lets the diaphragm sit neutral so the tank can accept expansion as soon as pressure rises."},
  {id:181, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"Without thermal-expansion control on a closed system, the most likely symptom is:", opts:["The T&P relief valve dripping or weeping when the heater fires","Low pressure","No hot water","A blocked drain"], correct:0, re:"Rising pressure from expansion can repeatedly lift the T&P relief valve, causing it to drip until expansion control is added."},
  {id:182, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"A water heater's temperature-and-pressure (T&P) relief valve is commonly set to open at no more than:", opts:["50 psi","150 psi","80 psi","300 psi"], correct:1, re:"Residential T&P valves are typically set to relieve at 150 psi (and about 210°F) to protect the tank from overpressure."},
  {id:183, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"An expansion tank that has lost its air charge will:", opts:["Work better","Raise pressure on purpose","Fill with water and stop absorbing expansion","Drain the heater"], correct:2, re:"A waterlogged tank cannot compress, so it no longer controls expansion and the relief valve may begin to drip again."},
  {id:184, block:2, sec:"Hot Water, Recirculation & Thermal Expansion", q:"A recirculation pump in a domestic hot-water loop is typically:", opts:["A high-pressure booster","A sewage ejector","A vacuum pump","A small circulator that moves water around the loop"], correct:3, re:"A small low-head circulator keeps hot water moving through the loop; it is not a pressure-boosting pump for the whole system."},
  {id:185, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"Where the public main pressure is too low to serve the building, the supply may be supplemented by:", opts:["An elevated tank, hydropneumatic system, or booster pump","A larger trap","A second vent","A floor drain"], correct:0, re:"Insufficient main pressure is overcome with an elevated (gravity) tank, a hydropneumatic pressure tank, or a water-pressure booster pump."},
  {id:186, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"An elevated (gravity) house tank supplies pressure to the building by:", opts:["Running a pump continuously","Using the height of stored water to create static pressure","Adding chemicals","Heating the water"], correct:1, re:"Water stored high in the building falls by gravity, and its elevation provides the static pressure to the floors below."},
  {id:187, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"A hydropneumatic (pressure) tank maintains pressure using:", opts:["A heating element","A check valve only","A captive volume of compressed air over the water","Gravity alone"], correct:2, re:"Compressed air trapped above the water in a sealed tank pushes the water out under pressure, smoothing pump cycling."},
  {id:188, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"In a tall building, water pressure on the upper floors is lower than on lower floors because of:", opts:["Smaller meters upstairs","Colder water","Fewer fixtures","The loss of static pressure with height"], correct:3, re:"Each foot of rise costs about 0.43 psi, so upper floors see lower pressure and may need a booster or zoning."},
  {id:189, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"A booster pump that can run with the discharge valve closed often needs protection against:", opts:["Overheating or excessive pressure (e.g., low-flow or relief protection)","Backflow only","Freezing only","Noise only"], correct:0, re:"A pump deadheading against a closed system can overheat or overpressurize, so controls or a relief path protect it."},
  {id:190, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"Tall buildings are often split into pressure zones so that lower floors do not experience:", opts:["Too little pressure","Excessively high pressure from the full column above","Backflow","Air binding"], correct:1, re:"Without zoning, the lowest floors would see the full static head of the water above them, exceeding safe pressure limits."},
  {id:191, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"Each fixture supply commonly has its own accessible:", opts:["Vent","Trap","Shutoff (stop) valve","Cleanout"], correct:2, re:"An accessible fixture shutoff lets a single fixture be isolated for repair without shutting down the whole building."},
  {id:192, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"The convention for fixture supply valves, facing the fixture, places hot water on the:", opts:["Right and cold on the left","Top","Bottom","Left and cold on the right"], correct:3, re:"By long-standing convention, hot is on the left and cold on the right at a fixture, matching user expectation."},
  {id:193, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"A backflow preventer or check valve protects the potable supply by:", opts:["Allowing flow in one direction only, toward the building","Raising pressure","Filtering the water","Reducing temperature"], correct:0, re:"These devices permit flow only toward the fixtures and block reverse flow that could draw contamination back into potable piping."},
  {id:194, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"A cross-connection is dangerous to the potable supply because it could allow:", opts:["Higher pressure","Non-potable water to enter the drinking-water piping","Faster drainage","Lower bills"], correct:1, re:"A cross-connection links potable and non-potable systems; if flow reverses, contaminated water can enter the drinking-water supply."},
  {id:195, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"Back-siphonage is a form of backflow caused by:", opts:["High downstream pressure","A closed valve","Negative (sub-atmospheric) pressure in the supply pulling water backward","Thermal expansion"], correct:2, re:"When supply pressure drops below atmospheric, suction can pull non-potable water back through a cross-connection into the system."},
  {id:196, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"A hose bibb supplying a garden hose should be protected against back-siphonage with:", opts:["A pressure regulator","A second meter","A larger pipe","A hose-connection vacuum breaker"], correct:3, re:"A hose-connection vacuum breaker breaks any siphon so contaminated water cannot be drawn back through the hose into the potable supply."},
  {id:197, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"An air gap protects the potable supply by providing:", opts:["An unobstructed vertical space between the outlet and the flood-level rim","A check valve","More pressure","A filter"], correct:0, re:"An air gap is a physical vertical separation so contaminated water can never be siphoned back into the supply outlet."},
  {id:198, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"Where a booster pump draws from a city main, codes are concerned that the suction could:", opts:["Improve water quality","Create negative pressure that back-siphons contamination into the main","Raise the main's pressure","Heat the main"], correct:1, re:"A pump pulling hard on the main can drop pressure below atmospheric and back-siphon contaminants, so protective measures are required."},
  {id:199, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"A reduced-pressure principle (RP) backflow assembly is used to protect the potable supply where:", opts:["No hazard exists","Pressure is below 8 psi","A high-hazard cross-connection must be protected","The pipe is plastic"], correct:2, re:"The RP assembly provides the highest level of protection and is required where a high-hazard cross-connection threatens the potable water."},
  {id:200, block:2, sec:"Booster Systems, Supply & Potable Protection", q:"After repairs that open the potable piping, a common step to protect water quality before use is to:", opts:["Add more pressure","Remove the meter","Lower the temperature","Flush and, where required, disinfect the affected piping"], correct:3, re:"Opened or new potable piping is flushed and, where required, disinfected so that contaminants introduced during work do not reach users."},
  {id:201, block:3, sec:"Drainage Fixture Units & Sizing", q:"A drainage fixture unit (DFU) is a measure used to:", opts:["Express the probable drainage load a fixture puts on the system","Set the water-supply pressure","Rate a pump's horsepower","Size the electrical circuit"], correct:0, re:"A DFU is a numeric value assigned to a fixture that represents its probable discharge load, used to size drains and sewers."},
  {id:202, block:3, sec:"Drainage Fixture Units & Sizing", q:"In the UPC fixture-unit tables, a single private lavatory is generally rated at about:", opts:["2 DFU","1 DFU","6 DFU","3 DFU"], correct:1, re:"A single lavatory carries roughly 1 drainage fixture unit because its discharge load is small."},
  {id:203, block:3, sec:"Drainage Fixture Units & Sizing", q:"A standard bathtub is commonly assigned a drainage load of about:", opts:["8 DFU","1 DFU","2 DFU","4 DFU"], correct:2, re:"A bathtub is typically rated near 2 drainage fixture units in the UPC fixture tables."},
  {id:204, block:3, sec:"Drainage Fixture Units & Sizing", q:"A domestic kitchen sink is generally rated for drainage at about:", opts:["1/2 DFU","6 DFU","10 DFU","2 DFU"], correct:3, re:"A residential kitchen sink is commonly assigned about 2 drainage fixture units."},
  {id:205, block:3, sec:"Drainage Fixture Units & Sizing", q:"A private water closet (1.6 gpf) is typically assigned a drainage load of about:", opts:["3 DFU","8 DFU","12 DFU","1 DFU"], correct:0, re:"A private water closet is commonly rated near 3 drainage fixture units, the largest single residential fixture load."},
  {id:206, block:3, sec:"Drainage Fixture Units & Sizing", q:"As the total drainage fixture units carried by a drain increase, the required pipe size generally:", opts:["Gets smaller","Gets larger","Becomes optional","Stays the same"], correct:1, re:"More fixture units mean more probable flow, so the drain must be larger to carry the load by gravity."},
  {id:207, block:3, sec:"Drainage Fixture Units & Sizing", q:"The maximum number of fixture units a horizontal drain may carry depends mainly on its diameter and its:", opts:["Length of the vent","Color","Slope (grade)","Brand of fitting"], correct:2, re:"Drain capacity tables are keyed to pipe diameter and slope, since a steeper grade lets a given pipe carry more fixture units."},
  {id:208, block:3, sec:"Drainage Fixture Units & Sizing", q:"When two or more fixtures discharge into one drain, that drain must be sized for:", opts:["Half of the total fixture units","One fixture unit regardless of count","Only the largest single fixture","The combined fixture-unit total of all fixtures served"], correct:3, re:"A common drain is sized for the sum of the fixture units it serves so it can carry the combined load."},
  {id:209, block:3, sec:"Drainage Fixture Units & Sizing", q:"A 2-inch horizontal branch drain is most appropriate for:", opts:["A floor drain or a small group of sinks and tubs","A 6-inch building sewer","A single water closet","A group of several water closets"], correct:0, re:"A 2-inch branch suits lighter fixtures such as floor drains, tubs, and sinks; water closets require a 3-inch minimum."},
  {id:210, block:3, sec:"Drainage Fixture Units & Sizing", q:"A fixture drain is defined as the drain that runs from:", opts:["The cleanout to the street","The trap of a fixture to the junction with any other drain pipe","The roof vent to the attic","The water meter to the fixture"], correct:1, re:"A fixture drain extends from the fixture trap to the point where it joins another drain pipe."},
  {id:211, block:3, sec:"Drainage Fixture Units & Sizing", q:"A drain pipe may never be smaller than:", opts:["The vent that serves it","Twice the trap size","The trap or trap arm of the fixture it serves","Half the trap size"], correct:2, re:"A fixture drain cannot be smaller than the trap and trap arm it serves, or flow would be restricted."},
  {id:212, block:3, sec:"Drainage Fixture Units & Sizing", q:"Compared with a private fixture, the same fixture in public use is often assigned:", opts:["No fixture units","Fewer fixture units","The same fixture units always","More fixture units"], correct:3, re:"Public fixtures are used more frequently, so the tables often assign them a higher fixture-unit value than private ones."},
  {id:213, block:3, sec:"Drainage Fixture Units & Sizing", q:"The minimum trap and drain size for a standard residential lavatory is:", opts:["1-1/4 inch","2 inch","3 inch","4 inch"], correct:0, re:"A lavatory uses a minimum 1-1/4 inch trap and drain because its discharge load is light."},
  {id:214, block:3, sec:"Drainage Fixture Units & Sizing", q:"A shower stall is typically served by a trap and drain of at least:", opts:["1-1/4 inch","2 inch","3 inch","4 inch"], correct:1, re:"A shower requires a minimum 2-inch trap and drain to carry its flow without backing up."},
  {id:215, block:3, sec:"Drainage Fixture Units & Sizing", q:"Oversizing a drain far beyond the required fixture units can be undesirable because it may:", opts:["Eliminate the need for a vent","Carry waste too quickly","Reduce the scouring action and let solids settle","Always cost less"], correct:2, re:"An oversized drain runs shallow, reducing the self-scouring velocity so solids can settle and clog the line."},
  {id:216, block:3, sec:"Drainage Fixture Units & Sizing", q:"The building drain and building sewer are sized from:", opts:["The number of windows","The water heater capacity","The roof area only","The total drainage fixture units of the whole building"], correct:3, re:"The building drain and sewer are sized for the total fixture-unit load of all fixtures discharging into them."},
  {id:217, block:3, sec:"Drainage Fixture Units & Sizing", q:"A kitchen sink with a food-waste disposer and a dishwasher generally:", opts:["May be assigned additional drainage load and a 2-inch drain","Must drain to the vent","Needs no trap","Carries the same load as a lavatory"], correct:0, re:"Added appliances increase the discharge, so the sink is typically given a 2-inch drain and a higher fixture-unit count."},
  {id:218, block:3, sec:"Drainage Fixture Units & Sizing", q:"Fixture-unit values exist so that designers can:", opts:["Avoid ever using tables","Convert dissimilar fixtures to a common load value for sizing","Set the gas pressure","Pick paint colors"], correct:1, re:"By converting every fixture to a common unit, mixed groups of fixtures can be added together to size the drain."},
  {id:219, block:3, sec:"Drainage Fixture Units & Sizing", q:"A 3-inch horizontal drain generally carries:", opts:["No water closets ever","Only one lavatory","More fixture units than a 2-inch drain at the same slope","Fewer fixture units than a 1-1/2 inch drain"], correct:2, re:"A larger diameter carries a greater fixture-unit load, so a 3-inch drain handles more than a 2-inch at the same grade."},
  {id:220, block:3, sec:"Drainage Fixture Units & Sizing", q:"When fixture-unit tables are used, the values represent:", opts:["The pipe's burst pressure","The vent length","Guaranteed simultaneous full flow from every fixture","A probable, not simultaneous-peak, load"], correct:3, re:"Fixture units reflect the probability that fixtures discharge at the same time, not all fixtures running at full flow at once."},
  {id:221, block:3, sec:"Slope, Grade & Drain Flow", q:"Horizontal drain pipes 2-1/2 inches and smaller are commonly sloped at a minimum of:", opts:["1/4 inch per foot","1 inch per foot","1/2 inch per foot","1/8 inch per foot"], correct:0, re:"Small horizontal drains are pitched at least 1/4 inch per foot so waste flows by gravity and solids are carried along."},
  {id:222, block:3, sec:"Slope, Grade & Drain Flow", q:"Larger horizontal drains (3 inches and larger) may be permitted to slope as little as:", opts:["1/4 inch per foot only","1/8 inch per foot where approved","1 inch per foot","No minimum"], correct:1, re:"Larger-diameter drains can be run at a flatter 1/8 inch per foot because their greater cross-section still maintains flow."},
  {id:223, block:3, sec:"Slope, Grade & Drain Flow", q:"A drain pipe sloped too steeply can cause problems because:", opts:["It always freezes","The vent is unnecessary","The liquid can run off and leave solids behind","Water flows uphill"], correct:2, re:"On a very steep grade the water outruns the solids, leaving them in the pipe where they accumulate and clog it."},
  {id:224, block:3, sec:"Slope, Grade & Drain Flow", q:"A horizontal drain that is run dead level (no slope) tends to:", opts:["Scour itself clean","Drain by capillary action","Flow faster","Allow waste to stand and solids to settle"], correct:3, re:"Without slope there is no gravity flow, so waste stands in the pipe and solids settle out and block it."},
  {id:225, block:3, sec:"Slope, Grade & Drain Flow", q:"A grade of 1/4 inch per foot means the pipe drops:", opts:["1/4 inch for each foot of horizontal run","1 foot for each 1/4 inch","4 inches per foot","1/4 inch over its entire length"], correct:0, re:"A 1/4-inch-per-foot grade drops the pipe a quarter inch of fall for every foot of horizontal distance."},
  {id:226, block:3, sec:"Slope, Grade & Drain Flow", q:"The purpose of maintaining proper drain slope is to keep the flow at a velocity that is:", opts:["As slow as possible","Self-scouring so solids are carried away","Exactly zero","Fast enough to splash out the vent"], correct:1, re:"Correct slope produces a self-scouring velocity that keeps solids moving and prevents the pipe from fouling."},
  {id:227, block:3, sec:"Slope, Grade & Drain Flow", q:"Over a 12-foot horizontal run, a 1/4-inch-per-foot grade gives a total fall of about:", opts:["No fall","1 inch","3 inches","12 inches"], correct:2, re:"At 1/4 inch per foot, twelve feet of run drops about 3 inches total (12 x 1/4 inch)."},
  {id:228, block:3, sec:"Slope, Grade & Drain Flow", q:"Drainage piping relies primarily on which force to move waste?", opts:["Vacuum from the vent","Water-supply pressure","Pump pressure","Gravity"], correct:3, re:"A gravity drainage system uses the slope of the pipe and gravity, not pressure, to carry waste to the sewer."},
  {id:229, block:3, sec:"Slope, Grade & Drain Flow", q:"A change of direction in a horizontal drain should be made with fittings that:", opts:["Maintain smooth flow, such as long-sweep or combination fittings","Reverse the slope","Eliminate slope","Turn flow abruptly at 90 degrees in the horizontal"], correct:0, re:"Smooth, sweeping fittings keep waste flowing and resist clogging, whereas sharp horizontal turns trap solids."},
  {id:230, block:3, sec:"Slope, Grade & Drain Flow", q:"If a horizontal drain must run flatter than its minimum slope, the usual remedy is to:", opts:["Use a smaller pipe","Increase the pipe diameter or install a pump","Remove the trap","Add more fittings"], correct:1, re:"A larger pipe carries the load at a flatter grade; where no fall is available, an approved sewage pump or ejector is used."},
  {id:231, block:3, sec:"Slope, Grade & Drain Flow", q:"A building drain below the level of the public sewer typically requires:", opts:["No special provision","A steeper gravity slope only","A sewage ejector or sump pump to lift the waste","A larger vent only"], correct:2, re:"Fixtures below the sewer cannot drain by gravity, so their waste is collected in a sump and pumped up to the gravity drain."},
  {id:232, block:3, sec:"Slope, Grade & Drain Flow", q:"On a sloped drain, the term 'invert' refers to:", opts:["The outside coating","The cleanout cap","The top inside of the pipe","The lowest inside surface of the pipe"], correct:3, re:"The invert is the lowest interior point of the pipe; slope is measured along the invert to set proper fall."},
  {id:233, block:3, sec:"Slope, Grade & Drain Flow", q:"Proper grade is checked during installation primarily to ensure:", opts:["Continuous fall toward the sewer with no bellies or back-pitch","The pipe is level","The vent is shorter","The pipe looks straight"], correct:0, re:"Verifying grade confirms a continuous fall to the sewer; a low spot (belly) or reverse pitch would hold waste and clog."},
  {id:234, block:3, sec:"Slope, Grade & Drain Flow", q:"A 'belly' (sag) in a horizontal drain is a defect because it:", opts:["Speeds drainage","Collects standing water and waste, leading to stoppages","Improves venting","Increases slope"], correct:1, re:"A sag creates a low spot where water and solids collect instead of flowing on, eventually blocking the line."},
  {id:235, block:3, sec:"Slope, Grade & Drain Flow", q:"Drain pipe must be supported at intervals close enough to:", opts:["Allow the pipe to flex freely","Eliminate the need for grade","Prevent sagging that would destroy the slope","Make the pipe heavier"], correct:2, re:"Adequate hangers and supports keep the pipe from sagging between supports, which would create bellies and ruin the grade."},
  {id:236, block:3, sec:"Traps & Trap Seals", q:"The depth of a trap's water seal is generally required to be not less than:", opts:["6 inches","1/2 inch","1 inch","2 inches"], correct:3, re:"A trap seal must be at least 2 inches deep so it reliably blocks sewer gas from entering the building."},
  {id:237, block:3, sec:"Traps & Trap Seals", q:"A trap's water seal is normally limited to a maximum depth of about:", opts:["4 inches","12 inches","24 inches","No maximum"], correct:0, re:"Trap seals are held between 2 and 4 inches deep; deeper seals can retain solids and are not standard."},
  {id:238, block:3, sec:"Traps & Trap Seals", q:"The 'weir' of a trap is:", opts:["The cleanout plug","The top of the downstream dip where water spills over into the trap arm","The vent opening","The trap's inlet from the fixture"], correct:1, re:"The weir is the crest over which water flows out of the trap into the trap arm; the seal is measured from the dip to the weir."},
  {id:239, block:3, sec:"Traps & Trap Seals", q:"A floor drain that is used infrequently may lose its trap seal to evaporation; this is commonly prevented with:", opts:["A deeper slope","A larger vent","A trap primer that adds water periodically","A second trap"], correct:2, re:"A trap primer feeds a small amount of water to the trap to replace evaporation and keep the seal intact."},
  {id:240, block:3, sec:"Traps & Trap Seals", q:"The most common trap used on residential fixtures is the:", opts:["Bell trap","S-trap","Drum trap","P-trap"], correct:3, re:"The P-trap, with its horizontal trap arm to a vent, is the standard approved fixture trap."},
  {id:241, block:3, sec:"Traps & Trap Seals", q:"Loss of a trap seal is dangerous mainly because it allows:", opts:["Sewer gas to enter the building","Higher water pressure","Backflow of potable water","Water hammer"], correct:0, re:"If the seal is lost, sewer gases (which can be toxic and flammable) pass through the empty trap into the occupied space."},
  {id:242, block:3, sec:"Traps & Trap Seals", q:"A trap can lose its seal by self-siphonage, which is:", opts:["Water freezing in the trap","The fixture discharge pulling the seal water out behind it","Evaporation over months","Wind across the vent"], correct:1, re:"Self-siphonage occurs when the fixture's own discharge creates suction that draws the seal water out of an unvented trap."},
  {id:243, block:3, sec:"Traps & Trap Seals", q:"A trap seal can also be lost by back-pressure, which is caused by:", opts:["Too much slope","A missing cleanout","Positive pressure in the drain blowing the seal out toward the fixture","Cold weather"], correct:2, re:"Positive pressure surging up the stack can push the seal water out of the trap into the fixture, breaking the seal."},
  {id:244, block:3, sec:"Traps & Trap Seals", q:"Each fixture, except those with integral traps, is required to have:", opts:["A shared trap with the next fixture","Two traps","No trap","Its own separate trap"], correct:3, re:"Each plumbing fixture must be separately trapped (unless its trap is built in), so sewer gas is blocked at every fixture."},
  {id:245, block:3, sec:"Traps & Trap Seals", q:"A water closet does not need a separate add-on trap because it:", opts:["Has an integral trap built into the fixture","Uses an air gap","Drains to a drum trap","Is vented differently"], correct:0, re:"A toilet has a trap molded into the china, so no additional external trap is installed on it."},
  {id:246, block:3, sec:"Traps & Trap Seals", q:"The distance from the trap weir to the dip determines the:", opts:["Trap arm length","Depth of the trap seal","Vent diameter","Slope of the drain"], correct:1, re:"The seal depth is the vertical distance between the dip and the weir; it must be at least 2 inches."},
  {id:247, block:3, sec:"Traps & Trap Seals", q:"A trap material such as ABS or chrome-plated brass must be:", opts:["Larger than the fixture outlet by 2 inches","Filled with sand","Smooth-bored and corrosion-resistant","Made of lead"], correct:2, re:"Approved trap materials are smooth-interior and resist corrosion so the seal holds and waste does not catch on rough surfaces."},
  {id:248, block:3, sec:"Traps & Trap Seals", q:"A standard P-trap should be installed so that the trap is:", opts:["Tilted to drain the seal","Inside the wall cavity only","Above the flood-level rim","Level and below the fixture, with the seal intact"], correct:3, re:"The trap is set level below the fixture so it retains a full 2-inch seal and the trap arm can pitch to the vent and drain."},
  {id:249, block:3, sec:"Trap Arm & Prohibited Traps", q:"An S-trap is prohibited primarily because it:", opts:["Tends to self-siphon and lose its seal","Cannot connect to a fixture","Is too large for any drain","Is too expensive"], correct:0, re:"An S-trap discharges straight down, which self-siphons the seal water out; a vented P-trap is required instead."},
  {id:250, block:3, sec:"Trap Arm & Prohibited Traps", q:"A bell trap is not permitted because it:", opts:["Has too deep a seal","Loses its seal easily and is hard to clean and maintain","Is only for toilets","Requires no vent"], correct:1, re:"Bell traps lose their seal readily and the removable parts are easily lost or clogged, so they are prohibited."},
  {id:251, block:3, sec:"Trap Arm & Prohibited Traps", q:"A drum trap is generally prohibited or discouraged because it:", opts:["Is too small to use","Self-scours well","Collects debris and is difficult to clean and properly vent","Has no seal"], correct:2, re:"Drum traps tend to accumulate solids and are hard to clean and vent, so modern codes restrict or prohibit them."},
  {id:252, block:3, sec:"Trap Arm & Prohibited Traps", q:"Double trapping a single fixture is prohibited because the air trapped between the two traps:", opts:["Speeds up the flow","Increases the trap seal depth","Improves the seal","Has no vent path and causes sluggish drainage and seal loss"], correct:3, re:"Air locked between two traps cannot escape, so drainage is slow and the seals tend to be pulled or pushed out."},
  {id:253, block:3, sec:"Trap Arm & Prohibited Traps", q:"A trap that depends on moving parts or a partition to retain its seal is:", opts:["Generally prohibited","Required for floor drains","The same as a P-trap","Preferred for sinks"], correct:0, re:"Traps relying on movable parts, interior partitions, or concealed mechanisms are prohibited because the seal is unreliable."},
  {id:254, block:3, sec:"Trap Arm & Prohibited Traps", q:"The trap arm is the portion of pipe that runs from the:", opts:["Vent terminal to the roof","Trap weir to the vent connection","Fixture rim to the trap","Cleanout to the sewer"], correct:1, re:"The trap arm extends from the trap's outlet (weir) to the point where the vent connects to the drain."},
  {id:255, block:3, sec:"Trap Arm & Prohibited Traps", q:"For a 1-1/4 inch trap arm, the maximum developed length to its vent is about:", opts:["No limit","6 inches","30 inches","10 feet"], correct:2, re:"A 1-1/4 inch trap arm may be up to about 30 inches (2-1/2 feet) long before the trap risks self-siphonage."},
  {id:256, block:3, sec:"Trap Arm & Prohibited Traps", q:"For a 1-1/2 inch trap arm, the maximum length to the vent is about:", opts:["8 feet","No limit","18 inches","42 inches"], correct:3, re:"A 1-1/2 inch trap arm is limited to roughly 42 inches (3-1/2 feet) of developed length to the vent."},
  {id:257, block:3, sec:"Trap Arm & Prohibited Traps", q:"For a 2-inch trap arm, the maximum developed length to the vent is about:", opts:["5 feet","20 feet","No limit","2 feet"], correct:0, re:"A 2-inch trap arm may extend about 5 feet to its vent under the trap-arm length table."},
  {id:258, block:3, sec:"Trap Arm & Prohibited Traps", q:"For a 3-inch trap arm, the maximum developed length to the vent is about:", opts:["3 feet","6 feet","30 feet","No limit"], correct:1, re:"A 3-inch trap arm is generally limited to about 6 feet of developed length to the vent."},
  {id:259, block:3, sec:"Trap Arm & Prohibited Traps", q:"The trap arm to its vent must, in no case, be shorter than:", opts:["Half the trap seal","The fixture width","Two times the trap arm diameter","The vent height"], correct:2, re:"The trap arm must be at least two pipe diameters long so the vent connection is not flooded by the trap discharge."},
  {id:260, block:3, sec:"Trap Arm & Prohibited Traps", q:"Limiting trap arm length protects the trap mainly against:", opts:["Water hammer","High supply pressure","Freezing","Self-siphonage that would empty the seal"], correct:3, re:"If the trap arm is too long, the falling discharge can siphon the seal out; the length limit prevents this self-siphonage."},
  {id:261, block:3, sec:"Trap Arm & Prohibited Traps", q:"The vent for a trap must connect to the trap arm:", opts:["At or above the level of the trap weir","Only at the fixture rim","Anywhere on the building drain","Below the trap weir"], correct:0, re:"The vent connects at or above the weir so the trap arm cannot fill and flood the vent opening with waste water."},
  {id:262, block:3, sec:"Trap Arm & Prohibited Traps", q:"A trap arm should not have a vertical drop greater than its own diameter before reaching the vent, to avoid:", opts:["A bigger trap","Re-creating the self-siphoning effect of an S-trap","A larger vent","A second trap"], correct:1, re:"Excess vertical fall in the trap arm turns it into an S-trap condition that can siphon the seal, so the drop is limited."},
  {id:263, block:3, sec:"Trap Arm & Prohibited Traps", q:"Connecting two fixtures so they share one trap (except for an approved set) is:", opts:["Allowed only for toilets","Always required","Generally prohibited","Recommended for tubs"], correct:2, re:"Fixtures must be individually trapped except for approved combinations, so sharing a single trap is generally not allowed."},
  {id:264, block:3, sec:"Vents & Venting", q:"The primary purpose of the venting system is to:", opts:["Supply water to fixtures","Heat the building","Carry waste to the sewer","Admit air to protect trap seals and equalize pressure in the drains"], correct:3, re:"Vents admit air so drainage flows smoothly and trap seals are not siphoned or blown out by pressure changes."},
  {id:265, block:3, sec:"Vents & Venting", q:"An individual (back) vent serves:", opts:["A single fixture trap","Only the building drain","Only the water heater","Every fixture in the building"], correct:0, re:"An individual vent connects to and protects the trap of one fixture, venting that fixture by itself."},
  {id:266, block:3, sec:"Vents & Venting", q:"A common vent is a single vent that serves:", opts:["No fixtures","Two fixtures connected at the same level","Eight or more water closets","The entire building"], correct:1, re:"A common vent serves two fixtures whose drains connect at the same level, venting both through one pipe."},
  {id:267, block:3, sec:"Vents & Venting", q:"A wet vent is a pipe that functions as:", opts:["A cleanout","Only a vent","Both a drain for one fixture and a vent for another","A water-supply line"], correct:2, re:"A wet vent carries the drainage of one fixture while also serving as the vent for another fixture in the group."},
  {id:268, block:3, sec:"Vents & Venting", q:"A circuit vent is used to vent:", opts:["The roof only","A water heater","A single lavatory","A battery of fixtures on a horizontal branch through one vent"], correct:3, re:"A circuit vent serves a row (battery) of fixtures on a horizontal branch, venting them with one vent ahead of the last fixture."},
  {id:269, block:3, sec:"Vents & Venting", q:"A vent stack is a vertical vent pipe installed primarily to:", opts:["Provide air circulation to and from the drainage system","Supply cold water","Hold the trap seal","Drain waste"], correct:0, re:"A vent stack is a vertical vent that circulates air through the drainage system, often relieving the stack at multiple floors."},
  {id:270, block:3, sec:"Vents & Venting", q:"A stack vent is:", opts:["A separate water pipe","The extension of a soil or waste stack above the highest branch","A grease trap","A trap primer"], correct:1, re:"A stack vent is the dry extension of a soil or waste stack above the highest horizontal drain connected to that stack."},
  {id:271, block:3, sec:"Vents & Venting", q:"Vent pipes must be graded and connected so they:", opts:["Run uphill to the roof","Hold standing water","Drain any condensate back to the drain by gravity","Slope away from the stack"], correct:2, re:"Vents are pitched so moisture drains back to the drainage pipe and cannot collect and block the air passage."},
  {id:272, block:3, sec:"Vents & Venting", q:"Where a vent terminates through a roof, it must extend above the roof at least about:", opts:["2 inches","3 feet","10 feet","6 inches"], correct:3, re:"A vent terminal must rise at least 6 inches above the roof so snow or ponding does not block it."},
  {id:273, block:3, sec:"Vents & Venting", q:"A vent terminal should be kept away from an openable window or air intake by at least:", opts:["10 feet horizontally (or terminate 3 feet above it)","100 feet","6 inches","1 foot"], correct:0, re:"To keep sewer gas out of the building, a vent must be at least 10 feet from an opening or terminate 3 feet above it."},
  {id:274, block:3, sec:"Vents & Venting", q:"The minimum size for most individual vents is:", opts:["1/2 inch","1-1/4 inch","3 inch","4 inch"], correct:1, re:"Vents are generally not smaller than 1-1/4 inch, and a vent should be at least half the diameter of the drain it serves."},
  {id:275, block:3, sec:"Vents & Venting", q:"A vent's diameter is generally required to be at least:", opts:["One-tenth the drain diameter","Twice the drain diameter","One-half the diameter of the drain it serves","The same as the water main"], correct:2, re:"A vent must be no less than half the diameter of the drain it serves, with a minimum size limit, to admit enough air."},
  {id:276, block:3, sec:"Vents & Venting", q:"An air admittance valve (AAV), where permitted, works by:", opts:["Pumping water","Replacing the trap","Releasing sewer gas to the room","Opening to admit air on negative pressure and sealing against positive pressure"], correct:3, re:"An AAV opens to let air in when the drain pulls a vacuum and closes under positive pressure so gas cannot escape."},
  {id:277, block:3, sec:"Vents & Venting", q:"A relief vent is provided mainly to:", opts:["Relieve pressure between the drainage stack and a horizontal branch","Supply hot water","Trap solids","Drain the fixtures"], correct:0, re:"A relief vent provides an extra air path so pressure differences in the stack do not affect the branch trap seals."},
  {id:278, block:3, sec:"Vents & Venting", q:"Vent piping that runs horizontally must stay above the:", opts:["Roof line","Flood-level rim of the fixtures it serves","Building drain only","Water meter"], correct:1, re:"Horizontal vent runs must be kept above the flood-level rim of the fixtures so waste water cannot flow into the vent."},
  {id:279, block:3, sec:"Vents & Venting", q:"A fixture that is not adequately vented is most likely to suffer from:", opts:["Excess slope","High water pressure","Slow, gurgling drainage and a siphoned trap seal","Frozen pipes"], correct:2, re:"Without a vent, the trap can be siphoned and air cannot enter, so the fixture drains slowly and gurgles as the seal is pulled."},
  {id:280, block:3, sec:"Vents & Venting", q:"In a wet-vented bathroom group, the wet vent is usually oversized so it can:", opts:["Hold more trap seal","Replace the building drain","Serve as a cleanout","Carry drainage and still pass air to vent the other fixtures"], correct:3, re:"The wet vent is enlarged so it can carry one fixture's discharge while still leaving an air path to vent the others."},
  {id:281, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A cleanout is provided in the drainage system to:", opts:["Give access to clear stoppages without cutting the pipe","Reduce pipe size","Hold the trap seal","Vent the line"], correct:0, re:"A cleanout provides access so a drain can be rodded or augered to clear a blockage without disassembling the pipe."},
  {id:282, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"On a long horizontal drain, cleanouts are generally required at intervals of not more than:", opts:["10 feet","100 feet of developed length","500 feet","1,000 feet"], correct:1, re:"A cleanout is required for each 100 feet (or fraction) of developed length on a horizontal drain so any point can be reached."},
  {id:283, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A cleanout is also required where the aggregate change of direction in a drain run exceeds about:", opts:["45 degrees","90 degrees","135 degrees","360 degrees"], correct:2, re:"An additional cleanout is required where horizontal changes of direction total more than 135 degrees, since bends resist rodding."},
  {id:284, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A cleanout must be installed at the upper terminal of:", opts:["The vent stack","The gas line","The water-supply line","Each horizontal drainage pipe run"], correct:3, re:"Each horizontal drainage run needs a cleanout at its upper end so a snake can be run downstream through the whole line."},
  {id:285, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"Cleanouts must be installed so they are:", opts:["Readily accessible for cleaning the drain","Always on the roof","Inside the trap seal","Buried and sealed permanently"], correct:0, re:"A cleanout is useless if it cannot be reached, so it must remain readily accessible for servicing the drain."},
  {id:286, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A cleanout may generally be omitted on a horizontal drain that is shorter than:", opts:["No exception exists","5 feet (unless it serves sinks or urinals)","50 feet","100 feet"], correct:1, re:"Very short horizontal drains under 5 feet may omit a cleanout, except where they serve sinks or urinals."},
  {id:287, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A grease interceptor (grease trap) is installed to:", opts:["Raise water pressure","Add water to the trap","Keep fats, oils, and grease out of the building sewer","Vent the kitchen"], correct:2, re:"A grease interceptor separates and holds fats, oils, and grease so they do not enter and clog the sewer system."},
  {id:288, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A grease interceptor is most often required on the drain from:", opts:["A lawn sprinkler","A roof drain","A residential bathtub","A commercial kitchen's sinks and dishwasher"], correct:3, re:"Commercial kitchens discharge heavy grease loads, so their warewashing fixtures drain through a grease interceptor."},
  {id:289, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A hydromechanical grease interceptor generally has a rated flow of not less than about:", opts:["20 gpm","200 gpm","2,000 gpm","2 gpm"], correct:0, re:"Code-rated hydromechanical grease interceptors typically start at about 20 gpm flow capacity."},
  {id:290, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A toilet (water closet) is generally not allowed to discharge through a grease interceptor because the interceptor is intended only for:", opts:["Sanitary sewage from toilets","Greasy waste, not human sewage","Storm water","Vent air"], correct:1, re:"Grease interceptors handle greasy fixture waste; toilet (black) waste is kept out so it does not foul the interceptor."},
  {id:291, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A sand or oil interceptor is used to keep:", opts:["Water in the trap","Grease only","Sand, oil, or other heavy materials out of the drainage system","Vent gas in the pipe"], correct:2, re:"Sand and oil interceptors separate heavy solids and petroleum products (as in garages and car washes) before the drain."},
  {id:292, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"The building drain is the lowest horizontal drainage piping that:", opts:["Supplies water","Vents the stacks","Runs on the roof","Receives the discharge of all the building's drains and carries it to the building sewer"], correct:3, re:"The building drain is the lowest part of the drainage system inside the building, collecting all waste and conveying it outside to the sewer."},
  {id:293, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"The building drain typically becomes the building sewer at a point about:", opts:["2 feet outside the building wall","At the roof vent","At the water meter","At the fixture trap"], correct:0, re:"By definition the building drain extends to about 2 feet outside the building wall, where it becomes the building sewer."},
  {id:294, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"The building sewer carries waste from the building drain to the:", opts:["Water heater","Public sewer or approved private disposal system","Roof drain","Vent terminal"], correct:1, re:"The building sewer conveys the building's waste from the building drain to the public sewer or an approved on-site disposal system."},
  {id:295, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"Rain (storm) water and roof drains are generally:", opts:["Connected to the vent","Discharged into the sanitary sewer with the toilets","Kept separate from the sanitary drainage system","Routed through the grease trap"], correct:2, re:"Storm water is normally kept out of the sanitary system and handled by a separate storm drainage system."},
  {id:296, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A cleanout at the junction of the building drain and building sewer lets a service technician:", opts:["Add a trap","Increase the slope","Vent the sewer","Rod the building sewer toward the street"], correct:3, re:"A cleanout near the building/sewer junction provides access to rod the building sewer out toward the public main."},
  {id:297, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"A building (house) trap, where used, is intended to:", opts:["Provide a single seal between the building drain and the public sewer","Pump waste uphill","Replace fixture traps","Vent the building"], correct:0, re:"A building trap places one seal on the building drain to block sewer gases from the main; many codes now restrict it in favor of fixture traps and venting."},
  {id:298, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"Underground building drainage pipe is usually required to be buried below the surface at least about:", opts:["1 inch","12 inches (1 foot)","6 feet","No minimum"], correct:1, re:"Drainage piping under or near a building is generally kept at least about 12 inches below grade to protect it from damage."},
  {id:299, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"The minimum size for a building drain or sewer serving one or more water closets is:", opts:["1-1/2 inch","2 inch","3 inch","No minimum"], correct:2, re:"Because a water closet requires a 3-inch drain, any building drain or sewer carrying a toilet must be at least 3 inches."},
  {id:300, block:3, sec:"Cleanouts, Interceptors & Building Drain", q:"Before backfilling an underground building sewer, the installer should:", opts:["Remove the cleanouts","Connect it to the vent","Skip any test","Test the line for leaks and confirm proper grade"], correct:3, re:"The sewer is tested for tightness and checked for continuous grade before backfilling, since defects are hard to fix once buried."},
  {id:301, block:4, sec:"Fixtures & Flush Systems", q:"A flushometer (flush valve) water closet differs from a tank-type toilet in that it:", opts:["Connects directly to the supply and meters water through a valve, with no storage tank","Always uses more than 5 gallons per flush","Stores its flush water in a gravity tank","Cannot be used in commercial buildings"], correct:0, re:"A flushometer connects directly to the water supply and releases a metered burst through a valve, so it needs no storage tank, which is why it is common in commercial restrooms."},
  {id:302, block:4, sec:"Fixtures & Flush Systems", q:"A flushometer valve requires the supply piping to provide:", opts:["Very low flow over a long time","No minimum pressure at all","Adequate flow-pressure to operate the valve quickly","Only gravity from a roof tank"], correct:2, re:"Because a flushometer discharges a short, high-rate burst, the branch must supply enough flow-pressure for the valve to work; undersized pipe starves it."},
  {id:303, block:4, sec:"Fixtures & Flush Systems", q:"A gravity-tank toilet creates its flush by:", opts:["A pump in the bowl","An electric solenoid","Compressed air only","Releasing the weight and volume of water stored in the tank"], correct:3, re:"A gravity toilet relies on the head and volume of water dropping from the tank to siphon the bowl, which is why tank-type units dominate homes."},
  {id:304, block:4, sec:"Fixtures & Flush Systems", q:"A dual-flush toilet is designed to:", opts:["Offer a reduced flush for liquid waste and a full flush for solids","Flush only with hot water","Use two separate water supplies","Require a flushometer valve"], correct:0, re:"Dual-flush units give a partial flush for liquids and a full flush for solids, saving water on the more frequent light flushes."},
  {id:305, block:4, sec:"Fixtures & Flush Systems", q:"The federal maximum flush volume for a standard new water closet is:", opts:["3.5 gallons per flush","5.0 gallons per flush","1.6 gallons per flush","2.5 gallons per flush"], correct:2, re:"The national standard caps a standard toilet at 1.6 gallons per flush; high-efficiency models use even less."},
  {id:306, block:4, sec:"Fixtures & Flush Systems", q:"A high-efficiency (WaterSense-labeled) toilet uses no more than:", opts:["1.6 gallons per flush","2.0 gallons per flush","1.28 gallons per flush","3.5 gallons per flush"], correct:2, re:"WaterSense toilets are limited to 1.28 gallons per flush, about a 20% saving over the 1.6-gpf federal standard."},
  {id:307, block:4, sec:"Fixtures & Flush Systems", q:"In California, the maximum flow rate allowed for a residential showerhead is:", opts:["1.8 gallons per minute","2.5 gallons per minute","3.0 gallons per minute","5.0 gallons per minute"], correct:0, re:"California limits showerheads to 1.8 gallons per minute; where several heads share one valve, their combined flow may not exceed that figure."},
  {id:308, block:4, sec:"Fixtures & Flush Systems", q:"When several showerheads are served by a single control valve, the combined flow rate must:", opts:["Be doubled for each head","Be unlimited","Not exceed the single-head limit at the test pressure","Be measured only at the meter"], correct:2, re:"California treats the heads on one valve as a unit; together they cannot exceed 1.8 gpm at 80 psi, so adding heads does not bypass the limit."},
  {id:309, block:4, sec:"Fixtures & Flush Systems", q:"A urinal flush valve in a public restroom is most often a:", opts:["Gravity tank","Hand-poured bucket","Foot-pump only","Flushometer (flush valve) type"], correct:3, re:"Urinals are typically served by flushometer valves connected directly to the supply, the same family of valve used on commercial toilets."},
  {id:310, block:4, sec:"Fixtures & Flush Systems", q:"A 'siphon-jet' bowl design refers to a water closet that:", opts:["Uses a jet of water to start a siphon and clear the bowl","Has no trap","Drains by air pressure only","Cannot hold a water seal"], correct:0, re:"A siphon-jet directs water through a jet at the trapway to prime the siphon, giving a strong, quiet flush and a large water surface."},
  {id:311, block:4, sec:"Fixtures & Flush Systems", q:"A floor-mounted toilet is sealed to the closet flange with:", opts:["Silicone tape","Solvent cement","Plumber's putty only","A wax ring (or approved gasket)"], correct:3, re:"A wax ring or listed waxless gasket seals the toilet horn to the flange so waste and sewer gas cannot escape at the floor."},
  {id:312, block:4, sec:"Fixtures & Flush Systems", q:"A ballcock (fill valve) inside a gravity toilet tank is responsible for:", opts:["Refilling the tank and bowl after a flush","Heating the water","Venting sewer gas","Closing the building shutoff"], correct:0, re:"The fill valve refills the tank to its set level and refeeds the bowl after each flush so the trap reseals and the tank is ready."},
  {id:313, block:4, sec:"Fixtures & Flush Systems", q:"The overflow tube in a toilet tank exists to:", opts:["Speed the flush","Replace the flapper","Increase tank pressure","Send excess water to the bowl instead of onto the floor"], correct:3, re:"If the fill valve fails to shut off, the overflow tube routes the extra water down into the bowl and out the drain rather than overflowing the tank."},
  {id:314, block:4, sec:"Fixtures & Flush Systems", q:"A pressure-assist toilet improves flushing by:", opts:["Using a roof tank","Eliminating the trap","Using building water pressure to compress air that boosts the flush","Adding a recirculating pump"], correct:2, re:"A pressure-assist vessel inside the tank uses line pressure to compress trapped air, which then forces water out with extra energy for a stronger flush."},
  {id:315, block:4, sec:"Fixtures & Flush Systems", q:"The flapper (flush valve seal) at the bottom of a gravity tank:", opts:["Heats the water","Vents the bowl","Reduces supply pressure","Opens to release tank water, then reseats to hold it"], correct:3, re:"Lifting the handle raises the flapper to dump the tank; once the tank empties the flapper drops and seals so the tank can refill."},
  {id:316, block:4, sec:"Fixture Clearances & Rough-in", q:"California requires the centerline of a water closet to be at least how far from a side wall or obstruction?", opts:["15 inches","8 inches","21 inches","30 inches"], correct:0, re:"The code requires not less than 15 inches from the toilet centerline to any side wall or obstruction so the fixture can be used comfortably."},
  {id:317, block:4, sec:"Fixture Clearances & Rough-in", q:"The minimum clear space required in front of a water closet is:", opts:["12 inches","6 inches","36 inches","24 inches"], correct:3, re:"At least 24 inches of clear space must be provided in front of a water closet for access and use."},
  {id:318, block:4, sec:"Fixture Clearances & Rough-in", q:"Two adjacent water closets must have their centerlines separated by at least:", opts:["15 inches","18 inches","30 inches","24 inches"], correct:2, re:"Centerline-to-centerline spacing between two toilets (or a toilet and a bidet) must be at least 30 inches."},
  {id:319, block:4, sec:"Fixture Clearances & Rough-in", q:"A standard residential toilet drain and trap arm must be at least:", opts:["1-1/2 inch","2 inch","2-1/2 inch","3 inch"], correct:3, re:"A water closet requires a 3-inch drain and trap arm to carry its discharge, larger than the branches serving sinks and tubs."},
  {id:320, block:4, sec:"Fixture Clearances & Rough-in", q:"The minimum trap and drain size for a lavatory (bathroom sink) is:", opts:["1-1/4 inch","1-1/2 inch","2 inch","3 inch"], correct:0, re:"A lavatory may use a 1-1/4-inch trap and drain, the smallest fixture trap the code permits."},
  {id:321, block:4, sec:"Fixture Clearances & Rough-in", q:"The minimum trap size for a kitchen sink is:", opts:["1-1/4 inch","3 inch","2 inch","1-1/2 inch"], correct:3, re:"A kitchen sink requires at least a 1-1/2-inch trap, larger than a lavatory because it carries more and greasier waste."},
  {id:322, block:4, sec:"Fixture Clearances & Rough-in", q:"A bathtub is served by a trap of at least:", opts:["1-1/4 inch","2 inch","1-1/2 inch","3 inch"], correct:2, re:"A bathtub uses a minimum 1-1/2-inch trap, the same minimum as a kitchen sink."},
  {id:323, block:4, sec:"Fixture Clearances & Rough-in", q:"A shower compartment must have a minimum finished interior area of, and contain a 30-inch circle of:", opts:["1024 square inches","576 square inches","720 square inches","2048 square inches"], correct:0, re:"A shower must enclose at least 1024 square inches of finished interior and be able to contain a 30-inch-diameter circle."},
  {id:324, block:4, sec:"Fixture Clearances & Rough-in", q:"A shower drain and its trap must be at least:", opts:["1-1/4 inch","1-1/2 inch","2 inch","4 inch"], correct:2, re:"A shower requires a minimum 2-inch drain and trap to carry its flow without backing up."},
  {id:325, block:4, sec:"Fixture Clearances & Rough-in", q:"A shower's required dimensions must be maintained from the drain up to a height of at least:", opts:["48 inches","60 inches","70 inches","84 inches"], correct:2, re:"The shower's clear interior must be kept to at least 70 inches above the drain, with only the valve, head, soap dishes, and grab bars allowed to project."},
  {id:326, block:4, sec:"Fixture Clearances & Rough-in", q:"The developed length of a trap arm (trap weir to vent) is limited mainly to prevent:", opts:["The trap seal from being siphoned out","Water from freezing","High water pressure","Excess noise only"], correct:0, re:"If the trap arm is too long, the drop can siphon the trap dry; the code limits its length so the seal is protected by the vent."},
  {id:327, block:4, sec:"Fixture Clearances & Rough-in", q:"A horizontal trap arm must never be less than how many pipe diameters from the trap weir to the vent?", opts:["One","Ten","Five","Two"], correct:3, re:"The trap arm must run at least two pipe diameters from the weir to the vent so the vent opening is not below the trap's discharge."},
  {id:328, block:4, sec:"Fixture Clearances & Rough-in", q:"A residential lavatory typically needs clear space in front of at least:", opts:["12 inches","30 inches","24 inches","6 inches"], correct:2, re:"Like a water closet, a lavatory is given at least 24 inches of clearance in front so it can be approached and used."},
  {id:329, block:4, sec:"Fixture Clearances & Rough-in", q:"Fixture supply stop valves at a sink or toilet are installed primarily to:", opts:["Reduce house pressure","Hold the trap seal","Vent the drain","Isolate that fixture for repair without shutting the whole house"], correct:3, re:"An accessible angle stop under each fixture lets that fixture be shut off for service while the rest of the building keeps water."},
  {id:330, block:4, sec:"Fixture Clearances & Rough-in", q:"Plumbing rough-in dimensions are the locations of supply and drain stub-outs set:", opts:["Before walls and finishes are closed in","After the walls are finished","Only at final inspection","After fixtures are set"], correct:0, re:"Rough-in fixes the height and position of the pipe stub-outs while the wall is open, so the finished fixtures land in the right place."},
  {id:331, block:4, sec:"Fixture Clearances & Rough-in", q:"A floor drain trap is most likely to lose its seal by:", opts:["Over-pressurization","Too small a vent","Excess slope","Evaporation when the drain is seldom used"], correct:3, re:"An infrequently used floor drain can evaporate dry and let sewer gas in, which is why trap primers or seldom-used floor drains need attention."},
  {id:332, block:4, sec:"Fixture Clearances & Rough-in", q:"A trap primer is provided to:", opts:["Add water to a floor-drain trap to keep its seal","Increase flush volume","Reduce gas pressure","Vent the stack"], correct:0, re:"A trap primer feeds a small amount of water to a floor-drain trap so the seal does not evaporate and admit sewer gas."},
  {id:333, block:4, sec:"Water Heaters — Relief & Safety", q:"A water heater's temperature-and-pressure (T&P) relief valve protects against:", opts:["Low supply pressure","Backflow into the city main","Excessive temperature and pressure inside the tank","Hard-water scale"], correct:2, re:"The T&P valve opens if the tank's temperature or pressure climbs too high, relieving it before the tank can rupture or explode."},
  {id:334, block:4, sec:"Water Heaters — Relief & Safety", q:"The discharge pipe from a T&P relief valve must:", opts:["Be smaller than the valve outlet","Drain by gravity with no valve and no trap","Connect directly into the building sewer","Loop upward to a high point"], correct:1, re:"The relief line must be full size, run downhill by gravity, contain no shutoff valve or trap, and end at an approved point so it can always discharge."},
  {id:335, block:4, sec:"Water Heaters — Relief & Safety", q:"The discharge pipe of a T&P valve must be the same size as, or not smaller than:", opts:["1/4 inch","The flue","The cold-water inlet","The valve outlet"], correct:3, re:"The discharge pipe must be at least the size of the relief-valve outlet for its full length so it does not restrict the relieving flow."},
  {id:336, block:4, sec:"Water Heaters — Relief & Safety", q:"A T&P discharge pipe terminating indoors must end no more than how high above the floor or receptor?", opts:["6 inches","2 inches","12 inches","24 inches"], correct:0, re:"An indoor relief discharge must terminate not more than 6 inches above the floor or waste receptor (and at least two pipe diameters), so a release is visible but cannot scald."},
  {id:337, block:4, sec:"Water Heaters — Relief & Safety", q:"The end of a T&P discharge pipe must:", opts:["Be threaded for a cap","Be valved for control","Have no threaded connection","Discharge upward"], correct:2, re:"The terminal end must not be threaded, so no one can cap, plug, or valve it and defeat the relief path."},
  {id:338, block:4, sec:"Water Heaters — Relief & Safety", q:"A shutoff valve or other restriction in a T&P relief discharge line is:", opts:["Required by code","Only allowed outdoors","Recommended for control","Prohibited"], correct:3, re:"No valve, tee, or reducer is allowed between the relief valve and the open end, because any restriction could block emergency discharge."},
  {id:339, block:4, sec:"Water Heaters — Relief & Safety", q:"A water heater set where a leak could cause damage (such as an attic or upper floor) requires:", opts:["A drain pan piped to an approved location","A second relief valve","A larger flue","No special provision"], correct:0, re:"A corrosion-resistant pan with its own drain to an approved point catches leakage and protects the structure below the heater."},
  {id:340, block:4, sec:"Water Heaters — Relief & Safety", q:"A water-heater drain pan drain line must be at least:", opts:["3/4 inch","1/2 inch","1-1/4 inch","2 inch"], correct:0, re:"The pan drain must be not less than 3/4 inch in diameter and run to an approved location so leakage is carried away."},
  {id:341, block:4, sec:"Water Heaters — Relief & Safety", q:"A cold-water full-way shutoff valve on a water heater must be located:", opts:["On the hot outlet","On the flue","On the relief discharge","On the cold supply to the heater"], correct:3, re:"A full-way shutoff is required on the cold-water supply line to the heater so the unit can be isolated for service."},
  {id:342, block:4, sec:"Water Heaters — Relief & Safety", q:"Why is a shutoff valve placed on the cold inlet rather than the hot outlet of a water heater?", opts:["So the tank can be isolated and drained for service","To raise outlet temperature","To reduce flue size","To eliminate the relief valve"], correct:0, re:"Closing the cold inlet isolates the tank from the supply so it can be drained and serviced; the hot side then has no feed."},
  {id:343, block:4, sec:"Water Heaters — Relief & Safety", q:"If a T&P valve repeatedly weeps or discharges, the correct response is to:", opts:["Cap the discharge pipe","Plug the valve","Find and fix the cause (excess temperature or pressure)","Remove the valve"], correct:2, re:"Frequent discharge signals real overtemperature or overpressure (often thermal expansion); the cause must be corrected, never the valve plugged."},
  {id:344, block:4, sec:"Water Heaters — Relief & Safety", q:"In a closed water system, thermal expansion at the water heater is best controlled by:", opts:["Removing the relief valve","A larger flue","An expansion tank on the cold supply","A second drain pan"], correct:2, re:"With a check valve or regulator making the system closed, an expansion tank absorbs the pressure rise from heating so the relief valve is not forced to weep."},
  {id:345, block:4, sec:"Water Heaters — Relief & Safety", q:"A T&P relief valve is typically rated to open on temperature at about:", opts:["120 degrees F","150 degrees F","210 degrees F","300 degrees F"], correct:2, re:"A standard T&P valve is set to relieve at about 210 degrees F on temperature (and commonly 150 psi on pressure) to prevent the water from flashing to steam."},
  {id:346, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"In California, a residential water heater must be braced against earthquakes with:", opts:["No straps","A single strap at the top","One strap at the bottom only","At least two straps, in the upper and lower thirds of the tank"], correct:3, re:"California requires the tank to be strapped in both its upper and lower thirds so it cannot topple during seismic shaking."},
  {id:347, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"The lower seismic strap on a water heater must be kept at least how far above the controls?", opts:["4 inches","1 inch","12 inches","24 inches"], correct:0, re:"The lower strap is placed in the bottom third but at least 4 inches above the gas controls so it does not interfere with them."},
  {id:348, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"A gas water heater installed in a residential garage generally must have its ignition source (burner) located:", opts:["At floor level","Exactly 6 inches above the floor","Below the floor","At least 18 inches above the floor unless listed FVIR"], correct:3, re:"In a garage the burner must be at least 18 inches above the floor to keep heavier-than-air flammable vapors from reaching it, unless the heater is listed flammable-vapor-ignition-resistant (FVIR)."},
  {id:349, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"A water heater in the path of a vehicle in a garage also requires:", opts:["A taller flue","Protection from physical impact (such as a bollard or barrier)","A larger relief valve","A second pan"], correct:1, re:"Where a vehicle could strike it, the heater must be guarded by a barrier or bollard so it is not damaged by impact."},
  {id:350, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"Combustion air openings for an enclosed gas water heater are typically provided as:", opts:["One opening at mid-height only","No openings","Two openings, one near the top and one near the bottom of the enclosure","A single floor drain"], correct:2, re:"The traditional method gives two permanent openings, one within 12 inches of the top and one within 12 inches of the bottom, so air can circulate for combustion."},
  {id:351, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"For two openings communicating directly with the outdoors, each opening must have a free area of at least:", opts:["1 square inch per 1000 Btu/hr","10 square inches per 1000 Btu/hr","1 square inch per 100 Btu/hr","1 square inch per 4000 Btu/hr"], correct:3, re:"When two openings communicate directly with outdoors (or via vertical ducts), each must be at least 1 square inch per 4000 Btu/hr of total appliance input."},
  {id:352, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"The two required combustion-air openings must be located:", opts:["Both within 12 inches of the floor","One within 12 inches of the top and one within 12 inches of the bottom","Both at the ceiling","Anywhere on one wall"], correct:1, re:"One opening goes within 12 inches of the top of the space and the other within 12 inches of the bottom so warm and cool air can exchange."},
  {id:353, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"A Type B gas vent serving an atmospheric (draft-hood) water heater is listed for a clearance to combustibles of:", opts:["0 inches","18 inches","6 inches","1 inch"], correct:3, re:"Double-wall Type B vent is listed for a 1-inch clearance to combustible material, far less than single-wall connector pipe requires."},
  {id:354, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"A gas vent (Type B) must terminate above the roof by at least:", opts:["2 feet (and per the vent's height table)","6 inches","No minimum","10 feet always"], correct:0, re:"A gas vent must extend at least 2 feet above the roof surface (and meet the listed height-versus-distance requirements) for proper draft and dispersion."},
  {id:355, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"The draft hood on an atmospheric gas water heater functions to:", opts:["Increase gas pressure","Filter the gas","Admit dilution air and relieve downdrafts so the burner vents stably","Store flue gas"], correct:2, re:"The draft hood lets dilution air in and spills excess draft, keeping the burner venting steadily and preventing pressure swings from backdrafting it."},
  {id:356, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"A tankless (demand) water heater differs from a storage type in that it:", opts:["Stores 40 gallons of hot water","Heats water only on demand, with no storage tank","Cannot use gas","Has no minimum flow to activate"], correct:1, re:"A tankless unit heats water instantaneously as it flows, avoiding the standby losses of a storage tank but needing a minimum flow to fire."},
  {id:357, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"Compared with a storage heater, a tankless water heater chiefly reduces:", opts:["Standby heat loss","Water pressure","Flue temperature to zero","The need for any venting"], correct:0, re:"Because it stores no hot water, a tankless heater eliminates the standby loss of keeping a tank hot, improving efficiency for low to moderate use."},
  {id:358, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"The 'first-hour rating' of a storage water heater describes:", opts:["Its warranty period","Its flue size","Its tank wall thickness","The gallons of hot water it can deliver in the first hour from full"], correct:3, re:"First-hour rating is the volume of hot water a fully heated storage tank can supply in one hour, combining stored volume and recovery."},
  {id:359, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"The 'recovery rate' of a water heater refers to:", opts:["How fast it can reheat water as it is drawn","How long the warranty lasts","The relief-valve setting","The strap spacing"], correct:0, re:"Recovery rate is how quickly the heater can raise incoming cold water to temperature; a higher input gives a higher recovery."},
  {id:360, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"A single-wall vent connector from a water heater to the chimney generally requires a clearance to combustibles of:", opts:["0 inches","1 inch","6 inches","No clearance is specified"], correct:2, re:"Single-wall connector pipe runs hot and typically needs 6 inches of clearance to combustibles, which is why double-wall Type B is often used in tight spaces."},
  {id:361, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"A water heater flue or vent connector should slope:", opts:["Downward toward the heater","Downhill to a trap","Perfectly level","Upward toward the vent (typically 1/4 inch per foot)"], correct:3, re:"The connector must rise toward the vent, commonly at least 1/4 inch per foot, so hot flue gases flow upward and draft is maintained."},
  {id:362, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"Insufficient combustion air to a gas water heater can cause:", opts:["Incomplete combustion and dangerous carbon monoxide","Improved efficiency","Lower flue temperature only","No effect at all"], correct:0, re:"Starved of air, the burner combusts incompletely and can produce carbon monoxide and sooting, which is why adequate combustion air is required."},
  {id:363, block:4, sec:"Water Heaters — Combustion, Venting & Seismic", q:"A direct-vent (sealed-combustion) water heater draws its combustion air from:", opts:["The room it sits in","Outdoors through a dedicated intake","The relief valve","The drain pan"], correct:1, re:"A direct-vent unit pulls combustion air from outdoors and vents outdoors through a sealed system, so it does not depend on room air."},
  {id:364, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"A common approved rigid material for fuel-gas piping in a building is:", opts:["PVC","ABS","Black (steel) pipe","Type M copper DWV"], correct:2, re:"Black steel pipe, commonly schedule 40, is a standard fuel-gas material; CSST and, where permitted, certain copper are also used."},
  {id:365, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"CSST stands for:", opts:["Cast steel supply tube","Coated soft solder tube","Corrugated stainless steel tubing","Central safety shutoff trap"], correct:2, re:"CSST is corrugated stainless steel tubing, a flexible listed gas-piping product installed according to its manufacturer's instructions."},
  {id:366, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"A CSST gas-piping system must be electrically bonded with a conductor not smaller than:", opts:["No. 6 AWG copper","No. 14 AWG copper","No. 18 AWG copper","No bonding is needed"], correct:0, re:"CSST must be bonded to the electrical grounding system with at least a No. 6 AWG copper conductor to dissipate energy from nearby lightning and reduce arcing."},
  {id:367, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"The main reason CSST must be bonded is to:", opts:["Reduce the risk of arcing and perforation from lightning energy","Increase gas pressure","Lower flue temperature","Speed up the flow of gas"], correct:0, re:"Bonding lowers the voltage that can build on thin-walled CSST during a lightning event, reducing the chance of arc-through that could ignite gas."},
  {id:368, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"A sediment trap (drip leg) at a gas appliance is installed to:", opts:["Reduce gas pressure","Vent the gas line","Increase flow","Catch dirt and moisture before they reach the appliance control"], correct:3, re:"The sediment trap collects debris and condensate so they settle out instead of fouling the appliance's gas valve or burner orifice."},
  {id:369, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"A sediment trap is most commonly formed from:", opts:["A check valve","A pressure regulator","A union only","A tee with a capped nipple on the bottom outlet"], correct:3, re:"The trap is usually a tee fitting with a capped vertical nipple below, so debris drops into the dead-end leg before the gas turns to the appliance."},
  {id:370, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"A sediment trap is required at the inlet of which appliances?", opts:["Only the gas meter","Water heaters, furnaces, and boilers (per code)","Only outdoor grills","None at all"], correct:1, re:"A sediment trap is required downstream of the shutoff at appliances such as water heaters, furnaces, and boilers; certain appliances like ranges may be exempt."},
  {id:371, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"Each gas appliance must have a shutoff valve that is:", opts:["Only at the meter","Readily accessible and in the same room, near the appliance","Behind the wall","Sealed shut"], correct:1, re:"An appliance shutoff must be in the same room and readily accessible near the appliance so gas can be cut for service or emergencies."},
  {id:372, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"A flexible gas appliance connector may have an overall length not exceeding:", opts:["3 feet","No limit","12 feet","6 feet"], correct:3, re:"A listed appliance connector is limited to 6 feet overall, and only one connector may be used per appliance."},
  {id:373, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"A flexible gas appliance connector must NOT:", opts:["Be listed","Pass through a wall, floor, partition, or be concealed","Connect to a shutoff valve","Be a single piece"], correct:1, re:"A connector cannot run through walls, floors, partitions, or ceilings, and cannot be concealed; building piping must extend to the same room as the appliance."},
  {id:374, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"Joining two flexible gas connectors together to gain length is:", opts:["Permitted","Not permitted","Required for ranges","Allowed outdoors only"], correct:1, re:"Only one connector is allowed per appliance; splicing two together is prohibited by the product standard and the code."},
  {id:375, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"An appliance shutoff valve for a flexible connector is installed:", opts:["Inside the appliance","At the meter only","On the roof","Where the connector attaches to the rigid building piping"], correct:3, re:"The shutoff is placed at the point the connector meets the fixed building piping, so it is reachable in the same room as the appliance."},
  {id:376, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"CSST is usually NOT permitted to be:", opts:["Installed indoors","Used at all","Left exposed to physical damage without protection","Connected to black pipe"], correct:2, re:"Where CSST could be struck or abraded it must be protected (for example with striker plates or sleeves), since its thin wall is easily damaged."},
  {id:377, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"Black steel gas pipe is joined by:", opts:["Threaded joints (or welding) with approved pipe-joint compound","Solvent cement","Crimp rings","A wax ring"], correct:0, re:"Steel gas pipe is threaded (or welded) and sealed with a thread compound listed for fuel gas; solvent cements are for plastics, not gas."},
  {id:378, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"Galvanized steel pipe is generally avoided for natural gas because:", opts:["It is too strong","Flaking zinc can clog controls and orifices","It cannot be threaded","It is not sold in the U.S."], correct:1, re:"Zinc galvanizing can flake off inside the pipe and lodge in valves and orifices, so black steel is preferred for fuel gas."},
  {id:379, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"Underground metallic gas piping is protected against corrosion by:", opts:["Leaving it bare","Filling it with oil","Painting it white only","Coating, wrapping, or using approved corrosion protection"], correct:3, re:"Buried metal gas pipe must be protected from corrosion by an approved coating, wrap, or cathodic means so it does not rust through."},
  {id:380, block:4, sec:"Fuel-Gas Piping — Materials & Components", q:"An appliance connector is certified to the standard:", opts:["ASTM D1785","ANSI Z21.24 / CSA 6.10","NEC Article 250","ASME B16.3 only"], correct:1, re:"Listed gas appliance connectors are certified to ANSI Z21.24/CSA 6.10, which limits them to 6 feet and to single-appliance use."},
  {id:381, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"Gas piping must be sized to supply:", opts:["Only the smallest appliance","Half the total load","The combined maximum demand of all connected appliances","Twice the meter rating"], correct:2, re:"The system is sized for the sum of the appliances' maximum input so all can operate at once without starving for gas."},
  {id:382, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"To size a branch of gas pipe you must know its length and the connected load expressed in:", opts:["Gallons per minute","Btu per hour (or cubic feet per hour)","Volts","Pounds of force"], correct:1, re:"Gas pipe is sized from the demand in Btu/hr (or cfh) and the developed length, read against the proper sizing table for the gas and pressure."},
  {id:383, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"For a given length and load, increasing the allowable pressure drop in a gas line lets you use:", opts:["A larger pipe","A smaller pipe","No pipe","A copper pipe only"], correct:1, re:"Allowing more pressure drop along a run means a smaller pipe can still deliver the required flow, which is reflected in the sizing tables."},
  {id:384, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"As the developed length of a gas pipe run increases, for the same load the required pipe size:", opts:["Decreases","Stays the same","Increases","Becomes zero"], correct:2, re:"Longer runs lose more pressure to friction, so a larger pipe is needed to carry the same Btu load the required distance."},
  {id:385, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"Standard low-pressure natural gas appliances in a home operate at a delivery pressure of about:", opts:["7 inches of water column","5 psi","60 psi","30 psi"], correct:0, re:"Typical residential natural gas is delivered at roughly 7 inches water column (about 1/4 psi); sizing tables are based on that low pressure."},
  {id:386, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"A new gas piping system must be:", opts:["Filled with water before use","Buried before testing","Pressure-tested for leaks before being placed in service","Left open to the air"], correct:2, re:"Gas piping is pressure-tested and proven leak-free before any gas is admitted and the system put into service."},
  {id:387, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"Under the Uniform/California code, a gas pressure test is generally held at not less than:", opts:["10 psi for at least 15 minutes","1 psi for 1 minute","100 psi for 1 hour","No pressure is required"], correct:0, re:"The standard field test is at least 10 psi held for at least 15 minutes (longer per the authority) with no perceptible drop in pressure."},
  {id:388, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"The test pressure for gas piping must be at least how many times the working pressure (with a stated floor)?", opts:["One-half","One and one-half times","Ten times","Equal to working pressure only"], correct:1, re:"The test pressure must be not less than 1-1/2 times the proposed working pressure, and in no case less than the code minimum, to prove the joints."},
  {id:389, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"During a gas pressure test, appliances rated below the test pressure must be:", opts:["Left connected and open","Isolated from the piping (valved off or disconnected)","Operated at full fire","Removed from the building"], correct:1, re:"Appliances not designed for the test pressure are isolated by closing their shutoffs or disconnecting them, so the test does not damage them."},
  {id:390, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"A gas pressure test is read with:", opts:["A thermometer","A gauge or manometer appropriate to the pressure","A voltmeter","A flow meter only"], correct:1, re:"The held test pressure is observed on a gauge or manometer suited to the range, and any perceptible drop signals a leak to be found and fixed."},
  {id:391, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"The sediment trap is normally located:", opts:["At the meter only","Downstream of the appliance shutoff, close to the appliance inlet","On the roof","Inside the appliance flue"], correct:1, re:"It is placed after the shutoff valve and as near the appliance inlet as practical, so it captures debris just before the gas enters the control."},
  {id:392, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"A gas leak is checked at joints with:", opts:["An open flame","Approved leak-detection solution (bubbles) or a listed detector","Bare hands","A wet rag"], correct:1, re:"Leaks are found with a noncorrosive bubble solution or a listed gas detector, never an open flame, which would be dangerous."},
  {id:393, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"An earthquake (seismic) gas shutoff valve is designed to:", opts:["Boost gas pressure","Automatically stop gas flow during strong shaking","Replace the meter","Heat the gas"], correct:1, re:"A seismic shutoff closes the gas during strong ground motion, reducing the risk of gas-fed fires after an earthquake."},
  {id:394, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"When two appliances share a gas line, the section feeding both must be sized for:", opts:["The larger appliance only","The smaller appliance only","The sum of both appliances' demand","Half of each"], correct:2, re:"A common section must carry the combined load of every appliance it serves; only the final branch to a single appliance carries that one load."},
  {id:395, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"A gas piping system that fails its pressure test by losing pressure indicates:", opts:["The pipe is the correct size","A leak that must be found and repaired before service","The gas is too cold","The meter is too large"], correct:1, re:"A drop during the test means a leak; it must be located and corrected, then the system retested, before gas is turned on."},
  {id:396, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"The purpose of an accessible appliance shutoff near a furnace or water heater is to:", opts:["Increase pressure","Allow gas to be shut to that appliance for service or emergency","Vent the flue","Size the pipe"], correct:1, re:"The local shutoff lets a technician or occupant isolate just that appliance quickly without shutting the whole building's gas."},
  {id:397, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"Before placing a repaired gas line back in service, the plumber should:", opts:["Skip any test","Re-pressure-test and confirm it holds, then purge air properly","Light all burners at once","Leave it open overnight"], correct:1, re:"After a repair the line is retested for tightness and then purged of air so only gas reaches the burners when relit."},
  {id:398, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"Gas piping sizing tables are entered using the gas type, allowable pressure drop, and the run's:", opts:["Color","Longest developed length","Installer's name","Outside temperature"], correct:1, re:"Sizing is based on the longest length of run (and the connected Btu load), so the most demanding path governs the pipe size selected."},
  {id:399, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"A drip leg differs from a sediment trap in that a drip leg primarily collects:", opts:["Electrical current","Liquid (condensate) that could otherwise reach the appliance","Excess pressure","Combustion air"], correct:1, re:"A drip leg gives liquids a low point to collect; in practice the same tee-and-capped-nipple also serves as the sediment trap catching dirt and moisture."},
  {id:400, block:4, sec:"Fuel-Gas Piping — Sizing & Testing", q:"An undersized gas line serving a furnace and water heater running together will most likely cause:", opts:["Higher efficiency","A pressure drop that starves the burners and causes poor combustion","Lower flue temperature only","No effect"], correct:1, re:"If the shared pipe is too small, simultaneous demand drops the pressure and starves the burners, causing weak flames and incomplete combustion."},
  {id:401, block:5, sec:"cross-connection", q:"A cross-connection is best defined as:", opts:["A junction of two potable water mains of different sizes","A tee fitting installed on a hot-water recirculation loop","The point where a building drain becomes the building sewer","Any actual or potential connection between a potable water system and a non-potable source"], correct:3, re:"A cross-connection is any actual or potential link through which contaminants could enter the potable supply. Controlling it is the central goal of backflow prevention."},
  {id:402, block:5, sec:"cross-connection", q:"Backflow is the undesired reversal of flow in a piping system caused by:", opts:["Excessive water velocity in the main","Backpressure or backsiphonage","Normal demand at downstream fixtures","Thermal expansion of the water heater"], correct:1, re:"Backflow occurs by backpressure (downstream pressure exceeds supply) or backsiphonage (negative supply pressure). Both can draw contaminants into the potable system."},
  {id:403, block:5, sec:"cross-connection", q:"Backsiphonage is created by:", opts:["A downstream pump pushing water back toward the main","A negative or reduced pressure in the potable supply piping","A boiler operating above street pressure","Closing a valve too quickly (water hammer)"], correct:1, re:"Backsiphonage results from negative (sub-atmospheric) pressure in the supply, such as a water-main break or heavy draw, that siphons non-potable water backward."},
  {id:404, block:5, sec:"cross-connection", q:"Backpressure backflow occurs when:", opts:["Supply pressure drops below atmospheric pressure","A faucet is left open during a main shutdown","The downstream system pressure exceeds the potable supply pressure","An air gap is provided at the fixture"], correct:2, re:"Backpressure backflow happens when a downstream source (a pump, boiler, or elevated tank) raises pressure above the supply, forcing flow backward."},
  {id:405, block:5, sec:"cross-connection", q:"In cross-connection control, a 'high hazard' (contaminant) connection is one that could:", opts:["Only affect the taste, odor, or color of the water","Cause illness, spread disease, or be lethal if consumed","Reduce flow at the most remote fixture","Increase the water bill for the customer"], correct:1, re:"A high hazard (contaminant) cross-connection involves substances that could cause sickness or death. It requires the highest protection, such as an air gap or RP assembly."},
  {id:406, block:5, sec:"cross-connection", q:"A 'low hazard' (pollutant) cross-connection is one that:", opts:["Could be lethal to a consumer","Always requires a reduced-pressure principle assembly","Cannot legally be protected by a double-check assembly","Would impair water quality (taste, odor, color) but not endanger health"], correct:3, re:"A low hazard (pollutant) connection affects the aesthetic quality of water without posing a health risk. A double-check assembly is typically acceptable protection."},
  {id:407, block:5, sec:"cross-connection", q:"Which device provides the highest, most positive protection against backflow?", opts:["An atmospheric vacuum breaker","A double-check valve assembly","A properly installed air gap","A hose-bibb vacuum breaker"], correct:2, re:"A correctly sized physical air gap is the most reliable backflow protection because there is no mechanical part to fail. It is suitable for the highest hazards."},
  {id:408, block:5, sec:"cross-connection", q:"The degree of backflow protection required for a given connection is selected primarily on the basis of:", opts:["The pipe material used downstream","The degree of hazard and the type of backflow possible","The age of the building","Whether the fixture is residential or commercial only"], correct:1, re:"Protection is matched to the degree of hazard (low vs high) and whether backpressure, backsiphonage, or both are possible. This determines which assembly is acceptable."},
  {id:409, block:5, sec:"cross-connection", q:"A direct cross-connection is one in which the non-potable source can be forced into the potable system by:", opts:["Backsiphonage only","An air gap","Evaporation","Backpressure (a continuous physical connection under pressure)"], correct:3, re:"A direct cross-connection is subject to backpressure because the contaminant source is physically piped to the potable system and can be pushed backward under pressure."},
  {id:410, block:5, sec:"cross-connection", q:"An indirect cross-connection (such as a submerged inlet open to atmosphere) is typically subject to:", opts:["Backsiphonage","Backpressure only","Thermal expansion only","Neither backpressure nor backsiphonage"], correct:0, re:"An indirect cross-connection (such as a submerged inlet open to atmosphere) is exposed to backsiphonage when supply pressure goes negative."},
  {id:411, block:5, sec:"cross-connection", q:"A classic example of a cross-connection hazard is:", opts:["A faucet spout terminating well above the flood-level rim","A hose submerged in a bucket of chemicals while connected to a sill cock","A vent terminal through the roof","A cleanout plug at the base of a stack"], correct:1, re:"A garden hose left submerged in a contaminant, attached to a hose bibb, is a textbook cross-connection that can backsiphon pollutants into the potable supply."},
  {id:412, block:5, sec:"cross-connection", q:"Cross-connection control programs are intended chiefly to protect:", opts:["The drainage and venting system","Fixtures from water hammer","The public potable water supply from contamination","The water heater from scale"], correct:2, re:"Cross-connection control exists to keep contaminants out of the public potable water system, safeguarding consumers from waterborne hazards."},
  {id:413, block:5, sec:"cross-connection", q:"Containment, in cross-connection terminology, refers to backflow protection installed:", opts:["At each individual fixture inside the building","Only on the fire-sprinkler riser","At the service connection (meter) to isolate the entire premises","Inside the water heater"], correct:2, re:"Containment protects the public main by placing an assembly at the service connection so the whole premises is isolated from the utility supply."},
  {id:414, block:5, sec:"cross-connection", q:"Isolation (fixture protection), as opposed to containment, means protecting against backflow:", opts:["At the property's service connection only","At the specific point of each hazard within the premises","On the water utility's side of the meter","Only at the building's highest fixture"], correct:1, re:"Isolation places protection at each internal cross-connection so a hazard cannot reach other parts of the building's own potable system."},
  {id:415, block:5, sec:"cross-connection", q:"Which connection would generally be classified as a HIGH hazard?", opts:["A residential dishwasher with an integral air gap","A drinking fountain","A lawn-irrigation system with chemical injection","A bathtub spout above the rim"], correct:2, re:"An irrigation system that can inject fertilizers or pesticides is a high (health) hazard and requires high-level protection such as an RP assembly."},
  {id:416, block:5, sec:"cross-connection", q:"A submerged inlet exists whenever a water-supply outlet:", opts:["Terminates above the flood-level rim of the receptor","Can be flooded so that the outlet sits below the liquid level it discharges into","Is fitted with an air gap","Discharges to an indirect waste receptor"], correct:1, re:"A submerged inlet is any supply outlet that can become covered by the liquid it serves, creating a backsiphonage cross-connection that must be protected."},
  {id:417, block:5, sec:"cross-connection", q:"A boiler or hydronic heating loop connected to the potable supply is chiefly a backflow concern because of:", opts:["Backsiphonage from low street pressure","Backpressure plus the chemical/thermal hazard of the boiler water","Aesthetic taste changes only","Excessive flow velocity"], correct:1, re:"A boiler operates above supply pressure (backpressure) and may contain treatment chemicals, so its make-up connection is a high-hazard backpressure concern."},
  {id:418, block:5, sec:"cross-connection", q:"An auxiliary or secondary water supply (such as a private well) tied to a premises served by city water is significant because it:", opts:["Creates a potential cross-connection that can contaminate the public main","Always improves potable water quality","Eliminates the need for any backflow device","Is exempt from cross-connection rules"], correct:0, re:"An unapproved auxiliary supply can backflow into the public system, so such premises typically require containment protection at the service."},
  {id:419, block:5, sec:"backflow-assemblies", q:"The minimum vertical air gap between a potable water outlet and the flood-level rim of a fixture is generally:", opts:["1 inch (25 mm)","1/2 inch (13 mm)","2 inches (51 mm)","3 inches (76 mm)"], correct:0, re:"The Plumbing Code sets a minimum air gap of 1 inch. Smaller outlets still require this absolute minimum even when the calculated gap would be less."},
  {id:420, block:5, sec:"backflow-assemblies", q:"As a rule, the minimum air gap should be at least how many times the effective opening (diameter) of the supply outlet?", opts:["One time","Two times","Six times","Four times"], correct:1, re:"The air gap must be at least twice the effective opening diameter (but never less than 1 inch) where the outlet is not near a wall."},
  {id:421, block:5, sec:"backflow-assemblies", q:"Where a supply outlet is close to one wall, the required air gap is increased to at least how many times the effective opening?", opts:["Three times","Two times","Four times","One and one-half times"], correct:0, re:"Near a wall the splash/obstruction effect increases the requirement to three times the effective opening. Multiple nearby walls require even more."},
  {id:422, block:5, sec:"backflow-assemblies", q:"The 'effective opening' used to size an air gap is:", opts:["The outside diameter of the supply pipe","The minimum cross-sectional area of the water-supply opening (its least diameter)","The flood-level rim length","The depth of the receptor"], correct:1, re:"Effective opening is the smallest cross-section of the discharge outlet. The air gap is measured from that opening down to the flood-level rim."},
  {id:423, block:5, sec:"backflow-assemblies", q:"A reduced-pressure principle (RP) backflow assembly consists of:", opts:["A single check valve and one test cock","An air inlet that opens only at atmospheric pressure","A vacuum breaker and a single shutoff","Two independent check valves with a differential relief valve between them"], correct:3, re:"An RP assembly has two independent check valves and a differential relief valve in the zone between them, plus shutoffs and four test cocks."},
  {id:424, block:5, sec:"backflow-assemblies", q:"The reduced-pressure principle assembly is acceptable for protecting against:", opts:["Backsiphonage only, low hazard","Backpressure only, low hazard","Neither backpressure nor backsiphonage","Both backpressure and backsiphonage, including high hazard"], correct:3, re:"The RP assembly protects against both backpressure and backsiphonage and is approved for high-hazard service, making it the most versatile testable assembly."},
  {id:425, block:5, sec:"backflow-assemblies", q:"The relief valve on an RP assembly discharges to atmosphere whenever:", opts:["Supply pressure rises above 80 psi","Both checks are holding tightly","Downstream demand is high","The zone between the checks loses its required pressure differential"], correct:3, re:"If either check leaks and the differential across the relief valve drops too low, the relief opens and dumps the zone to atmosphere—its fail-safe action."},
  {id:426, block:5, sec:"backflow-assemblies", q:"An RP assembly is described as 'fail-safe to atmosphere' because:", opts:["A check failure causes the relief valve to spill, signaling and preventing backflow","It seals tighter as it fails","It silently passes water if it fails","It requires no testing"], correct:0, re:"A failed check opens the relief valve, dumping water externally rather than allowing contaminated water through—both a safeguard and a visible warning."},
  {id:427, block:5, sec:"backflow-assemblies", q:"A double-check valve assembly (DCVA) is made up of:", opts:["One check valve plus an atmospheric vent","A relief valve between two checks","Two independent spring-loaded check valves in series with shutoffs and test cocks","A single check with a vacuum breaker"], correct:2, re:"A DCVA uses two independent spring-loaded checks in series, two shutoff valves, and test cocks—but no relief valve to atmosphere."},
  {id:428, block:5, sec:"backflow-assemblies", q:"A double-check valve assembly is generally approved for:", opts:["High-hazard (health) connections","Backsiphonage only","Low-hazard (pollutant) connections subject to backpressure or backsiphonage","No backflow conditions"], correct:2, re:"The DCVA suits low-hazard situations with backpressure or backsiphonage. It is not approved for high-hazard (contaminant) connections."},
  {id:429, block:5, sec:"backflow-assemblies", q:"The key physical difference between a DCVA and an RP assembly is that the RP also has:", opts:["A second shutoff valve","Test cocks","A larger inlet","A differential relief valve in the central zone"], correct:3, re:"Both have two checks and shutoffs; only the RP adds the differential relief valve, which is what qualifies it for high-hazard protection."},
  {id:430, block:5, sec:"backflow-assemblies", q:"An atmospheric vacuum breaker (AVB) protects against:", opts:["Backpressure only","Both backpressure and backsiphonage","Thermal expansion","Backsiphonage only"], correct:3, re:"An AVB guards only against backsiphonage. It must never be installed where it could be subjected to backpressure."},
  {id:431, block:5, sec:"backflow-assemblies", q:"An atmospheric vacuum breaker must be installed so that its critical level is at least:", opts:["At or below the flood-level rim","6 inches above the highest downstream piping and flood-level rim","1 inch above the highest downstream piping and flood-level rim","12 inches above the flood-level rim"], correct:1, re:"An AVB must sit at least 6 inches above the highest downstream outlet and the flood-level rim so the air inlet can break a siphon properly."},
  {id:432, block:5, sec:"backflow-assemblies", q:"A shutoff valve, check valve, or other control downstream of an atmospheric vacuum breaker is:", opts:["Required for proper operation","Prohibited, because it can hold pressure on the AVB","Recommended for convenience","Allowed if it is a ball valve"], correct:1, re:"No valve may be placed downstream of an AVB; any downstream control could subject it to continuous pressure or backpressure, which it cannot handle."},
  {id:433, block:5, sec:"backflow-assemblies", q:"An atmospheric vacuum breaker is not designed to be under continuous water pressure for more than about:", opts:["1 hour","24 hours continuously without limit","12 hours","Any length of time is fine"], correct:2, re:"An AVB is designed for intermittent use and should not be under continuous pressure beyond roughly 12 hours, or its disc may stick and fail."},
  {id:434, block:5, sec:"backflow-assemblies", q:"A pressure vacuum breaker (PVB) differs from an AVB in that the PVB:", opts:["Can be kept under continuous pressure and protects against backsiphonage","May not be tested","Protects against backpressure","Must be installed below the flood-level rim"], correct:0, re:"A PVB has a spring-loaded air inlet and an internal check, so it may remain under continuous pressure. Like the AVB, it protects only against backsiphonage, not backpressure."},
  {id:435, block:5, sec:"backflow-assemblies", q:"A pressure vacuum breaker assembly must have its critical level installed at least:", opts:["6 inches above the highest downstream piping and flood-level rim","12 inches above the highest downstream piping and flood-level rim","1 inch above the flood-level rim","Level with the highest outlet"], correct:1, re:"A PVB's critical level must be at least 12 inches above the highest downstream outlet and flood-level rim, higher than the AVB requirement."},
  {id:436, block:5, sec:"backflow-assemblies", q:"Hose-threaded outlets (sill cocks/hose bibbs) supplying potable water must be protected by:", opts:["A reduced-pressure assembly only","A double-check detector assembly","A nonremovable hose-bibb vacuum breaker (or equivalent)","No protection if outdoors"], correct:2, re:"Hose outlets require a nonremovable hose-bibb vacuum breaker to prevent backsiphonage through an attached hose, a very common cross-connection."},
  {id:437, block:5, sec:"backflow-assemblies", q:"A hose-bibb vacuum breaker is required to be 'nonremovable' so that:", opts:["It can be reused on other faucets","It increases the hose flow rate","It cannot be easily taken off, defeating the backflow protection","It can be tested annually"], correct:2, re:"Making the breaker nonremovable (set screw broken off) keeps the protection permanently in place so a user cannot remove it and create a hazard."},
  {id:438, block:5, sec:"backflow-assemblies", q:"Which backflow protection is NOT field-testable with a gauge and works only by physical separation?", opts:["Air gap","Reduced-pressure principle assembly","Double-check valve assembly","Pressure vacuum breaker assembly"], correct:0, re:"An air gap has no moving parts and is verified by measurement, not a test gauge. The RP, DCVA, and PVB are mechanical assemblies that are field-tested."},
  {id:439, block:5, sec:"backflow-assemblies", q:"How many test cocks does a typical RP or double-check assembly have for field testing?", opts:["One","Two","Six","Four"], correct:3, re:"These assemblies are furnished with four test cocks, allowing a tester to read pressures across each check and the relief valve (on an RP)."},
  {id:440, block:5, sec:"backflow-assemblies", q:"During testing of an RP assembly, the differential relief valve must open before the zone differential drops below approximately:", opts:["2 psi","1 psi","10 psi","20 psi"], correct:0, re:"Standards require the relief valve to open at no less than about 2 psi differential, ensuring it spills before the central zone loses its protective pressure."},
  {id:441, block:5, sec:"backflow-assemblies", q:"In an RP assembly, the central zone between the two checks is maintained at a pressure that is:", opts:["Higher than the supply pressure","Equal to downstream pressure","Always atmospheric","Lower than the supply pressure but above atmospheric"], correct:3, re:"The zone is held at a reduced pressure—below supply yet above atmosphere—so that any leak past the first check is detected and relieved."},
  {id:442, block:5, sec:"backflow-assemblies", q:"Mechanical backflow prevention assemblies (RP, DCVA, PVB) generally must be tested for proper operation:", opts:["Only at the time of installation","Every ten years","Upon installation and at least annually (periodically) thereafter","Never, once installed"], correct:2, re:"Testable assemblies must be tested at installation and at least annually by a certified tester, because internal seals and springs can degrade over time."},
  {id:443, block:5, sec:"backflow-assemblies", q:"A backflow assembly should be installed where it is:", opts:["Buried directly in soil for protection","Concealed inside a finished wall","Submerged to prevent freezing","Accessible for testing, maintenance, and relief-valve discharge"], correct:3, re:"Assemblies must be accessible so they can be tested and repaired, and an RP must drain freely; it may not be installed where it could be flooded."},
  {id:444, block:5, sec:"backflow-assemblies", q:"A reduced-pressure principle assembly may NOT be installed:", opts:["In a below-grade pit or vault subject to flooding","Above grade in a heated room","On a horizontal run with clearance below the relief port","Where it is accessible for testing"], correct:0, re:"Because its relief valve discharges to atmosphere, an RP cannot be placed in a pit that could flood and submerge the relief opening, defeating its protection."},
  {id:445, block:5, sec:"backflow-assemblies", q:"The air-inlet (vent) port of an atmospheric or pressure vacuum breaker functions by:", opts:["Opening to admit air and break a vacuum when supply pressure falls","Sealing the supply when pressure is high","Discharging water continuously","Reducing the downstream pressure"], correct:0, re:"When supply pressure drops, the air-inlet opens and lets atmospheric air in, breaking the siphon so contaminated water cannot be drawn back."},
  {id:446, block:5, sec:"backflow-assemblies", q:"A barometric-loop method of backsiphonage protection relies on a pipe loop rising at least about:", opts:["10 feet","20 feet","50 feet","35 feet"], correct:3, re:"A barometric loop must rise roughly 35 feet so atmospheric pressure cannot lift water over the loop, preventing backsiphonage. It does not stop backpressure."},
  {id:447, block:5, sec:"backflow-assemblies", q:"Which assembly is commonly used on a low-hazard fire-sprinkler system that may see backpressure?", opts:["Atmospheric vacuum breaker","Hose-bibb vacuum breaker","Double-check detector assembly","Air gap"], correct:2, re:"A double-check detector assembly is common on low-hazard fire systems; it stops backpressure and backsiphonage and includes a metered bypass to detect leaks."},
  {id:448, block:5, sec:"backflow-assemblies", q:"A spill-resistant vacuum breaker (SVB) is essentially a pressure vacuum breaker that:", opts:["Protects against backpressure","May be installed below the flood-level rim","Minimizes spillage of water during normal operation","Requires no minimum mounting height"], correct:2, re:"An SVB is a PVB variant designed to limit water spillage when pressurized. It still protects only against backsiphonage and needs the same elevated critical level."},
  {id:449, block:5, sec:"backflow-assemblies", q:"An atmospheric vacuum breaker must be installed:", opts:["Upstream of all valves","On the discharge (downstream) side of the last valve, above the flood-level rim","Below the fixture it serves","In a buried valve box"], correct:1, re:"The AVB goes on the discharge side of the last valve and above the flood-level rim, so no valve can hold pressure on it and the siphon break is effective."},
  {id:450, block:5, sec:"backflow-assemblies", q:"Indirect waste from a commercial dishwasher or food-prep sink must discharge to the receptor through:", opts:["A direct hard pipe to the sewer","A double-check valve assembly on the drain","An air gap","A hose-bibb vacuum breaker on the drain"], correct:2, re:"Indirect waste from food-related equipment must discharge through an air gap into the receptor so sewage cannot back up into the equipment."},
  {id:451, block:5, sec:"backflow-assemblies", q:"When testing a double-check valve assembly, each check valve is required to hold a minimum static differential of at least:", opts:["0.5 psi","5 psi","10 psi","1 psi"], correct:3, re:"Each check of a DCVA must hold at least 1 psi in the direction of flow against reverse pressure to pass, demonstrating it seats tightly."},
  {id:452, block:5, sec:"backflow-assemblies", q:"Only a backflow assembly that is approved/listed for the use should be installed, meaning it has been:", opts:["Painted the correct color","Tested and listed by a recognized standard/laboratory and accepted by the authority","Manufactured domestically","Installed by the homeowner"], correct:1, re:"Assemblies must be of an approved (listed) type and model accepted by the authority having jurisdiction, ensuring they meet recognized performance standards."},
  {id:453, block:5, sec:"backflow-assemblies", q:"The chief limitation shared by both atmospheric and pressure vacuum breakers is that they:", opts:["Cannot be installed outdoors","Must be tested daily","Cannot be used on irrigation systems","Do not protect against backpressure"], correct:3, re:"Neither vacuum breaker protects against backpressure—they only break backsiphonage. Where backpressure is possible, a check-type assembly is required."},
  {id:454, block:5, sec:"backflow-assemblies", q:"Thermal expansion control is needed on a closed system because a backflow device or check:", opts:["Lowers the water heater temperature","Eliminates any possibility of backflow downstream","Increases fixture flow rates","Prevents the heated water from expanding back into the main, raising pressure"], correct:3, re:"When a check or backflow assembly closes the supply, heated water cannot expand back into the main, so an expansion tank is needed to control the rising pressure."},
  {id:455, block:5, sec:"backflow-assemblies", q:"A double-check detector assembly differs from a standard DCVA by adding:", opts:["A second relief valve","An atmospheric vent","A small metered bypass loop to detect leakage or unauthorized use","A third main check valve"], correct:2, re:"The detector version adds a metered bypass around the main checks so small flows (a leak or theft) register on the meter, useful on fire systems."},
  {id:456, block:5, sec:"backflow-assemblies", q:"An RP assembly installed outdoors above grade typically still requires:", opts:["Installation below the frost line in a sealed pit","Removal of all test cocks","Freeze protection and clearance for the relief valve to discharge freely","Direct burial in soil"], correct:2, re:"An above-grade RP needs protection from freezing and adequate air gap/clearance at the relief port so it can discharge without being submerged."},
  {id:457, block:5, sec:"ca-code", q:"The California Plumbing Code is codified as:", opts:["Title 8 of the California Code of Regulations","Title 16, Part 2 of the California Code of Regulations","Title 25, Part 1 of the California Code of Regulations","Title 24, Part 5 of the California Code of Regulations"], correct:3, re:"The California Plumbing Code is Part 5 of Title 24 (the California Building Standards Code) in the California Code of Regulations."},
  {id:458, block:5, sec:"ca-code", q:"The California Plumbing Code is based on (adopted from) which model code?", opts:["The International Plumbing Code (IPC)","The National Standard Plumbing Code","The Uniform Plumbing Code (UPC) published by IAPMO","The International Residential Code (IRC)"], correct:2, re:"California adopts the Uniform Plumbing Code (UPC), published by IAPMO, with state amendments, as its Plumbing Code (Title 24, Part 5)."},
  {id:459, block:5, sec:"ca-code", q:"Title 24 of the California Code of Regulations is collectively known as the:", opts:["California Labor Code","California Health and Safety Code","California Building Standards Code","California Vehicle Code"], correct:2, re:"Title 24 is the California Building Standards Code; its parts include the Building, Plumbing, Mechanical, Electrical, and Energy codes among others."},
  {id:460, block:5, sec:"ca-code", q:"When a local jurisdiction adopts the California Plumbing Code, it may:", opts:["Adopt more stringent amendments based on local climatic, geological, or topographical conditions","Delete the entire code","Ignore state minimums entirely","Apply a different state's code"], correct:0, re:"Local agencies may amend the state code to be more restrictive when justified by local conditions, but the state code sets the baseline minimum standards."},
  {id:461, block:5, sec:"ca-code", q:"Under the Safe Drinking Water Act and California law, 'lead free' for pipes, fittings, and fixtures means a weighted-average lead content of the wetted surfaces not exceeding:", opts:["0.25 percent","8.0 percent","2.0 percent","5.0 percent"], correct:0, re:"'Lead free' is a weighted average of no more than 0.25 percent lead across the wetted surfaces of pipes, fittings, and fixtures used for potable water."},
  {id:462, block:5, sec:"ca-code", q:"For solder and flux used on potable-water piping, the 'lead free' maximum lead content is:", opts:["0.25 percent","2.0 percent","0.2 percent","5.0 percent"], correct:2, re:"Solder and flux for potable water must contain no more than 0.2 percent lead, a stricter figure than the 0.25 percent weighted average for wetted surfaces."},
  {id:463, block:5, sec:"ca-code", q:"The lead-free requirements for potable plumbing products apply to components that:", opts:["Convey or dispense water for human consumption (drinking or cooking)","Only carry hot water","Are only used in drainage systems","Are buried below grade only"], correct:0, re:"Lead-free rules cover products that convey or dispense water for human consumption, including kitchen and bathroom faucets and other potable end-use devices."},
  {id:464, block:5, sec:"ca-code", q:"The California Plumbing Code's primary stated purpose is to provide minimum requirements that protect:", opts:["Manufacturers' market share","Only the building owner's investment","Aesthetic design choices","The public health, safety, and welfare"], correct:3, re:"Like its model UPC, the California Plumbing Code exists to safeguard public health, safety, and welfare through minimum plumbing standards."},
  {id:465, block:5, sec:"ca-code", q:"Which body adopts and publishes California's building standards, including the Plumbing Code?", opts:["The U.S. Environmental Protection Agency","The Contractors State License Board","The Federal Plumbing Authority","The California Building Standards Commission"], correct:3, re:"The California Building Standards Commission adopts and publishes Title 24, coordinating the state agencies that propose plumbing and other standards."},
  {id:466, block:5, sec:"ca-code", q:"Materials and products used in a California plumbing installation generally must be:", opts:["Manufactured only in California","Listed/approved to the referenced standards and accepted by the authority having jurisdiction","The least expensive available","Recycled from prior projects"], correct:1, re:"Products must comply with the standards referenced in the code and be acceptable to the AHJ, ensuring proven materials are used in potable and DWV systems."},
  {id:467, block:5, sec:"ca-code", q:"When a conflict exists between the California Plumbing Code and a more restrictive local amendment lawfully adopted, the installer must follow:", opts:["Whichever is less restrictive","The more restrictive lawfully adopted requirement","The manufacturer's catalog only","A neighboring jurisdiction's rule"], correct:1, re:"Where a lawfully adopted local amendment is more restrictive, it governs. The code sets minimums, and stricter local rules prevail when properly adopted."},
  {id:468, block:5, sec:"ca-code", q:"The California Plumbing Code is republished on a code-adoption cycle of approximately every:", opts:["Year","Ten years","Twenty years","Three years"], correct:3, re:"California's building standards, including the Plumbing Code, are generally published on a three-year cycle, with intervening supplements as needed."},
  {id:469, block:5, sec:"ca-code", q:"Under the code, the 'authority having jurisdiction' (AHJ) refers to:", opts:["The plumbing supply house","The agency or official responsible for enforcing the code and approving the installation","The pipe manufacturer","The property owner"], correct:1, re:"The AHJ is the enforcing body or official (commonly the local building department) that interprets the code, issues permits, and approves work."},
  {id:470, block:5, sec:"ca-code", q:"Alternate materials or methods not specifically prescribed by the code may be used only if:", opts:["The authority having jurisdiction approves them as equivalent in quality and safety","The contractor prefers them","They are cheaper than code-listed options","They are common in another state"], correct:0, re:"The code allows alternates when the AHJ finds them equivalent to the prescribed requirements in performance, safety, and quality—not at the installer's sole discretion."},
  {id:471, block:5, sec:"ca-code", q:"Potable water piping in California must be protected from contamination, which the code achieves chiefly through:", opts:["Larger pipe diameters","Cross-connection control and approved backflow protection","Higher water pressure","Color-coded fixtures"], correct:1, re:"The code's water-supply provisions require cross-connection control and backflow prevention to keep the potable system free of contamination."},
  {id:472, block:5, sec:"ca-code", q:"A recognized third-party certification mark on a potable-water product indicates it:", opts:["Is exempt from the code","Has been tested to applicable health-effects and performance standards","Was installed by a licensed contractor","Is the cheapest option"], correct:1, re:"A certification mark shows the product met applicable standards (including lead-content and health-effects standards) and is suitable for potable water use."},
  {id:473, block:5, sec:"ca-code", q:"The minimum standards in the California Plumbing Code represent:", opts:["The maximum that may ever be installed","Optional guidelines with no force of law","Requirements only for new construction","The least acceptable level of work; better practice is allowed"], correct:3, re:"Code requirements are minimums. An installer may exceed them, but may not provide less protection than the code mandates."},
  {id:474, block:5, sec:"ca-code", q:"Compliance with the California Plumbing Code is legally required because the code is:", opts:["A voluntary trade recommendation","A manufacturer's warranty document","An internal company policy","Adopted into law as a regulation (Title 24) enforceable by jurisdictions"], correct:3, re:"As an adopted state regulation, the California Plumbing Code carries the force of law and is enforced by local building officials."},
  {id:475, block:5, sec:"permits-inspect", q:"Before beginning most plumbing installations, a contractor must first:", opts:["Complete the work, then notify the city","Obtain a plumbing permit from the authority having jurisdiction","Schedule the final inspection only","Post a notice at the supply house"], correct:1, re:"A permit must be secured before work starts so the jurisdiction can review the scope and schedule required inspections at the proper stages."},
  {id:476, block:5, sec:"permits-inspect", q:"The rough-in (rough) plumbing inspection generally takes place:", opts:["After walls and finishes are installed","After piping is installed but before it is concealed or covered","Only after the building is occupied","Before any pipe is set in place"], correct:1, re:"Rough-in inspection occurs when DWV, water, and gas piping are installed and still exposed, so the inspector can verify the work before it is concealed."},
  {id:477, block:5, sec:"permits-inspect", q:"The water test on a DWV system requires the system to be filled with water to provide a head of at least:", opts:["5 feet","1 foot","20 feet","10 feet"], correct:3, re:"The DWV water test fills the section to at least a 10-foot head above the highest fitting in that section, then holds it to check for leaks."},
  {id:478, block:5, sec:"permits-inspect", q:"When testing DWV with air instead of water, the code generally requires a gauge pressure of at least:", opts:["5 psi","1 psi","20 psi","50 psi"], correct:0, re:"An air test of the DWV system is held at not less than 5 psi (or 10 inches of mercury), held without loss for the required period."},
  {id:479, block:5, sec:"permits-inspect", q:"A DWV test (water or air) must be held without leakage for a minimum of about:", opts:["15 minutes","5 seconds","60 minutes","1 minute"], correct:0, re:"The DWV test must hold for at least 15 minutes with no drop, demonstrating the drainage and vent piping is tight before concealment."},
  {id:480, block:5, sec:"permits-inspect", q:"The water-supply (distribution) piping is typically tested and proved tight using an air-pressure test of about:", opts:["50 psi","5 psi","10 psi","200 psi"], correct:0, re:"Potable water-supply piping is commonly tested at 50 psi air (or at working water pressure) and must hold without leaking for at least 15 minutes."},
  {id:481, block:5, sec:"permits-inspect", q:"When tested for tightness, the water-distribution piping must withstand the test without leaking for at least:", opts:["5 minutes","1 hour","15 minutes","24 hours"], correct:2, re:"Whether tested by air or by the working water pressure, the supply piping must hold for no less than 15 minutes without leakage."},
  {id:482, block:5, sec:"permits-inspect", q:"Fuel-gas piping for an ordinary low-pressure system is commonly proved tight before use with an air or inert-gas test of at least about:", opts:["10 psi","1 psi","100 psi","0.5 psi"], correct:0, re:"Low-pressure gas piping is typically tested at not less than 10 psi and held for the required time; verify the exact value for the system's operating pressure and code edition."},
  {id:483, block:5, sec:"permits-inspect", q:"On a test requiring a pressure of 10 psi or less, the code requires a gauge with graduated increments of:", opts:["0.10 psi or less","1.0 psi or less","5 psi or less","10 psi or less"], correct:0, re:"Low-pressure tests (10 psi or less) must use a gauge readable in increments of 0.10 psi or finer so small losses can be detected accurately."},
  {id:484, block:5, sec:"permits-inspect", q:"The final plumbing inspection is performed:", opts:["Before any piping is installed","When all plumbing work and fixtures are complete and ready for use","Only on the gas system","At the same time as the rough-in"], correct:1, re:"The final inspection occurs after fixtures are set and the system is complete, verifying everything operates properly and meets code before occupancy."},
  {id:485, block:5, sec:"permits-inspect", q:"Work that has been covered or concealed before the required inspection generally must be:", opts:["Left as is and approved later","Reported only on the final inspection","Uncovered or otherwise made available for inspection at the inspector's direction","Ignored if the contractor is licensed"], correct:2, re:"If required inspections are bypassed and work is concealed, the AHJ may require it to be uncovered so the installation can be verified."},
  {id:486, block:5, sec:"permits-inspect", q:"Who is responsible for notifying the authority and requesting required inspections at the proper stages?", opts:["The water utility","The permit holder (contractor) doing the work","The fixture manufacturer","The neighboring property owner"], correct:1, re:"The permit holder must call for inspections at each required stage; the work may not proceed past a required inspection until it is approved."},
  {id:487, block:5, sec:"permits-inspect", q:"A newly installed backflow prevention assembly installed under permit must be:", opts:["Concealed before inspection","Installed without any testing","Tested by a certified tester and the results provided to the authority","Approved verbally only"], correct:2, re:"Newly installed testable assemblies must be tested by a certified backflow tester, with the passing results submitted to the authority for acceptance."},
  {id:488, block:5, sec:"permits-inspect", q:"During a required piping test, the system must be observed:", opts:["With pressure applied only momentarily","Only after fixtures are connected","To hold the test pressure for the full required duration without leakage","While water is actively running through it"], correct:2, re:"A valid pressure test holds the specified pressure for the full required time with no measurable loss, confirming the system is leak-free."},
  {id:489, block:5, sec:"permits-inspect", q:"If an inspection reveals a code violation, the contractor must generally:", opts:["Conceal the work quickly","Continue and fix it after occupancy","Switch to a different permit","Correct the deficiency and request re-inspection before proceeding"], correct:3, re:"Identified violations must be corrected and re-inspected; the installation cannot lawfully proceed past a failed inspection until the issue is resolved."},
  {id:490, block:5, sec:"permits-inspect", q:"A plumbing permit is typically required for which of the following?", opts:["Clearing a stoppage in an existing trap with a plunger","Replacing a faucet washer","Installing new water, gas, or DWV piping or replacing a water heater","Cleaning a fixture aerator"], correct:2, re:"New piping and significant work such as water-heater replacement require a permit; minor repairs and routine maintenance generally do not."},
  {id:491, block:5, sec:"c36-scope", q:"The CSLB C-36 Plumbing classification authorizes a contractor to provide:", opts:["A safe water supply and proper disposal of fluid waste in structures and fixed works","Only electrical wiring","Structural framing only","Roofing and siding"], correct:0, re:"The C-36 scope covers furnishing a safe, adequate water supply and the proper disposal of fluid waste—the core of potable supply and drainage work."},
  {id:492, block:5, sec:"c36-scope", q:"Which of the following is within the scope of a C-36 plumbing contractor?", opts:["Installing water heaters, gas piping, backflow preventers, and DWV systems","Installing the building's main electrical service panel","Pouring structural foundations","Installing HVAC ductwork as the primary trade"], correct:0, re:"The C-36 covers water-supply and DWV systems, fuel-gas piping and appliances, water heaters, and backflow prevention—the trade's recognized plumbing work."},
  {id:493, block:5, sec:"c36-scope", q:"A C-36 plumbing contractor performing work that falls outside the plumbing classification must:", opts:["Hold or subcontract to the appropriate license classification for that work","Proceed without restriction","Ignore licensing for incidental work","Obtain a federal permit only"], correct:0, re:"Work outside the C-36 scope requires the proper classification; a contractor cannot self-perform unrelated trades without the corresponding license."},
  {id:494, block:5, sec:"c36-scope", q:"The CSLB contractor classifications, including the C-36, are established under:", opts:["Federal OSHA regulations","The Uniform Plumbing Code","Title 24, Part 6","California Code of Regulations, Title 16 (Contractors State License Board rules)"], correct:3, re:"Contractor classifications such as the C-36 are defined in Title 16 of the California Code of Regulations, the CSLB's regulatory framework."},
  {id:495, block:5, sec:"c36-scope", q:"A C-36 plumbing contractor's installation of medical gas or earthquake-actuated gas shutoff valves is:", opts:["Outside the C-36 scope entirely","Reserved exclusively to a general engineering (A) license","Permitted only with an electrical license","Within the recognized scope of the C-36 plumbing classification"], correct:3, re:"The C-36 scope includes plumbing-related work such as medical gas piping and seismic gas shutoff valves, in addition to water, DWV, and fuel-gas systems."},
  {id:496, block:5, sec:"safety", q:"Under OSHA excavation rules, a protective system (sloping, shoring, or shielding) is generally required for trenches at a depth of:", opts:["2 feet or more","10 feet or more","5 feet or more (unless in stable rock)","20 feet or more"], correct:2, re:"Trenches 5 feet deep or greater require a protective system unless excavated entirely in stable rock, to guard workers against cave-ins."},
  {id:497, block:5, sec:"safety", q:"For an excavation 20 feet or more in depth, the protective system must be:", opts:["Designed by (or based on tabulated data approved by) a registered professional engineer","Chosen by any worker on site","Omitted because it is too deep","Replaced with a warning sign only"], correct:0, re:"Excavations 20 feet or deeper require a protective system designed by a registered professional engineer (or PE-approved tabulated data) due to the severe cave-in risk."},
  {id:498, block:5, sec:"safety", q:"Excavated spoil and materials must be kept back from the edge of a trench by at least:", opts:["2 feet","6 inches","10 feet","It may be placed at the edge"], correct:0, re:"Spoil piles and equipment must be set back at least 2 feet from the trench edge so their weight and falling material do not trigger a collapse."},
  {id:499, block:5, sec:"safety", q:"A safe means of egress (ladder, ramp, or stairway) must be provided in trenches 4 feet or deeper so workers travel no more than:", opts:["10 feet laterally to reach it","25 feet laterally to reach it","50 feet laterally to reach it","100 feet laterally to reach it"], correct:1, re:"In trenches 4 feet or more deep, a means of egress must be within 25 feet of lateral travel for any worker, allowing quick escape."},
  {id:500, block:5, sec:"safety", q:"Before excavating, a plumber should contact the regional one-call (811) service to:", opts:["Have existing underground utilities located and marked","Order pipe materials","Schedule the final inspection","Obtain a plumbing permit"], correct:0, re:"Calling 811 before digging gets buried utilities located and marked, preventing dangerous and costly strikes to gas, electric, water, and other lines."}
];
